use std::fs;
use std::path::{Path, PathBuf};

use serde::{Deserialize, Serialize};

/// Application configuration.
#[derive(Debug, Default, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct Config {
    pub storage: StorageConfig,
    pub editor: EditorConfig,
    pub ui: UiConfig,
}

/// Storage paths configuration.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct StorageConfig {
    pub central: PathBuf,
    pub local: PathBuf,
}

/// Editor defaults.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct EditorConfig {
    pub autosave: bool,
    pub autosave_interval_secs: u64,
    pub tab_width: u8,
    pub line_numbers: bool,
}

/// UI defaults.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(default)]
pub struct UiConfig {
    pub note_panel_pct: u16,
}

impl Default for StorageConfig {
    fn default() -> Self {
        let data_dir = dirs::data_dir().unwrap_or_else(|| PathBuf::from(".")).join("duir");
        Self {
            central: data_dir,
            local: PathBuf::from(".duir"),
        }
    }
}

impl Default for EditorConfig {
    fn default() -> Self {
        Self {
            autosave: true,
            autosave_interval_secs: 30,
            tab_width: 4,
            line_numbers: false,
        }
    }
}

impl Default for UiConfig {
    fn default() -> Self {
        Self { note_panel_pct: 50 }
    }
}

impl Config {
    /// Load config by checking (in order):
    /// 1. `.duir/config.toml` (project-local)
    /// 2. `~/.duirrc` (user shorthand)
    /// 3. `$XDG_CONFIG_HOME/duir/config.toml` (global)
    ///
    /// Falls back to defaults if none found.
    #[must_use]
    pub fn load() -> Self {
        // Project-local
        let local = Path::new(".duir/config.toml");
        if let Some(cfg) = Self::try_load(local) {
            return cfg;
        }

        // User shorthand
        if let Some(home) = dirs::home_dir() {
            let rc = home.join(".duirrc");
            if let Some(cfg) = Self::try_load(&rc) {
                return cfg;
            }
        }

        // XDG global
        if let Some(config_dir) = dirs::config_dir() {
            let global = config_dir.join("duir").join("config.toml");
            if let Some(cfg) = Self::try_load(&global) {
                return cfg;
            }
        }

        Self::default()
    }

    fn try_load(path: &Path) -> Option<Self> {
        let content = fs::read_to_string(path).ok()?;
        toml::from_str(&content).ok()
    }

    /// Write config to the given path.
    ///
    /// # Errors
    /// Returns an error if the file cannot be written.
    pub fn write_to(&self, path: &Path) -> crate::Result<()> {
        let content = toml::to_string_pretty(self).map_err(|e| crate::OmelaError::Other(e.to_string()))?;
        if let Some(parent) = path.parent() {
            fs::create_dir_all(parent).map_err(|e| crate::OmelaError::io(path, e))?;
        }
        fs::write(path, content).map_err(|e| crate::OmelaError::io(path, e))?;
        Ok(())
    }

    /// Initialize a local `.duir/` directory with config and empty data dir.
    ///
    /// # Errors
    /// Returns an error if the directory cannot be created.
    pub fn init_local(&self) -> crate::Result<()> {
        let dir = Path::new(".duir");
        fs::create_dir_all(dir).map_err(|e| crate::OmelaError::io(dir, e))?;
        self.write_to(&dir.join("config.toml"))?;
        Ok(())
    }

    /// Check if a local `.duir/` directory exists.
    #[must_use]
    pub fn has_local() -> bool {
        Path::new(".duir").is_dir()
    }

    /// Get all storage directories to load from (central + local if present).
    #[must_use]
    pub fn storage_dirs(&self) -> Vec<PathBuf> {
        let mut dirs = vec![self.storage.central.clone()];
        if Self::has_local() {
            dirs.push(self.storage.local.clone());
        }
        dirs
    }
}

use std::io::{Read, Write};

use base64::Engine;
use base64::engine::general_purpose::STANDARD as BASE64;

use crate::error::{OmelaError, Result};
use crate::model::TodoItem;

/// Payload that gets encrypted: the children and note of a node.
#[derive(serde::Serialize, serde::Deserialize)]
struct EncryptedPayload {
    note: String,
    items: Vec<TodoItem>,
}

/// Encrypt a node's children and note with a passphrase.
/// Sets `cipher` and clears `items`/`note` on the item.
///
/// # Errors
/// Returns an error if encryption fails.
pub fn encrypt_item(item: &mut TodoItem, passphrase: &str) -> Result<()> {
    let payload = EncryptedPayload {
        note: item.note.clone(),
        items: item.items.clone(),
    };
    let json = serde_json::to_string(&payload)?;

    let recipient = age::scrypt::Recipient::new(age::secrecy::SecretString::from(passphrase.to_owned()));

    let recipients: Vec<Box<dyn age::Recipient>> = vec![Box::new(recipient)];
    let encryptor = age::Encryptor::with_recipients(recipients.iter().map(std::convert::AsRef::as_ref))
        .map_err(|e| OmelaError::Other(format!("Encryption setup error: {e}")))?;

    let mut encrypted = Vec::new();
    let mut writer = encryptor
        .wrap_output(&mut encrypted)
        .map_err(|e| OmelaError::Other(format!("Encryption error: {e}")))?;

    writer
        .write_all(json.as_bytes())
        .map_err(|e| OmelaError::Other(format!("Encryption write error: {e}")))?;
    writer
        .finish()
        .map_err(|e| OmelaError::Other(format!("Encryption finish error: {e}")))?;

    item.cipher = Some(BASE64.encode(&encrypted));
    item.items.clear();
    item.note.clear();
    item.unlocked = false;
    item.folded = true;

    Ok(())
}

/// Decrypt a node's cipher text with a passphrase.
/// Restores `items` and `note`, marks as unlocked.
///
/// # Errors
/// Returns an error if decryption fails (wrong password or corrupt data).
pub fn decrypt_item(item: &mut TodoItem, passphrase: &str) -> Result<()> {
    let cipher_b64 = item
        .cipher
        .as_ref()
        .ok_or_else(|| OmelaError::Other("Node is not encrypted".to_owned()))?;

    let encrypted = BASE64
        .decode(cipher_b64)
        .map_err(|e| OmelaError::Other(format!("Base64 decode error: {e}")))?;

    let decryptor =
        age::Decryptor::new(encrypted.as_slice()).map_err(|e| OmelaError::Other(format!("Decryption error: {e}")))?;

    let identity = age::scrypt::Identity::new(age::secrecy::SecretString::from(passphrase.to_owned()));

    let mut reader = decryptor
        .decrypt(std::iter::once(&identity as &dyn age::Identity))
        .map_err(|_| OmelaError::Other("Wrong password".to_owned()))?;

    let mut json = String::new();
    reader
        .read_to_string(&mut json)
        .map_err(|e| OmelaError::Other(format!("Decryption read error: {e}")))?;

    let payload: EncryptedPayload = serde_json::from_str(&json)?;

    item.note = payload.note;
    item.items = payload.items;
    item.unlocked = true;
    item.folded = false;

    Ok(())
}

/// Remove encryption from a node permanently.
pub fn strip_encryption(item: &mut TodoItem) {
    item.cipher = None;
    item.unlocked = false;
}

/// Check if any node in a subtree is encrypted.
#[must_use]
pub fn has_encrypted_in_subtree(item: &TodoItem) -> bool {
    if item.is_encrypted() {
        return true;
    }
    item.items.iter().any(has_encrypted_in_subtree)
}

/// Saved plaintext state of a node: (path, note, children).
pub type SavedNodeState = (Vec<usize>, String, Vec<TodoItem>);

/// Re-encrypt all unlocked nodes in a tree before saving.
/// Returns the items that were re-encrypted so they can be restored after save.
///
/// # Errors
/// Returns an error if encryption fails.
pub fn lock_for_save<S: std::hash::BuildHasher>(
    items: &mut [TodoItem],
    passwords: &std::collections::HashMap<Vec<usize>, String, S>,
    path_prefix: &[usize],
) -> crate::Result<Vec<SavedNodeState>> {
    let mut saved_state = Vec::new();

    for (i, item) in items.iter_mut().enumerate() {
        let mut path = path_prefix.to_vec();
        path.push(i);

        // Recurse into children first
        let child_saved = lock_for_save(&mut item.items, passwords, &path)?;
        saved_state.extend(child_saved);

        // If this node is unlocked, prepare it for save
        if item.unlocked
            && let Some(pw) = passwords.get(&path)
        {
            let note_backup = item.note.clone();
            let items_backup = item.items.clone();

            // Only re-encrypt if cipher is stale (None = invalidated by edits)
            if item.cipher.is_none() {
                encrypt_item(item, pw)?;
            } else {
                // Cipher is still valid — just clear plaintext for save
                item.items.clear();
                item.note.clear();
                item.unlocked = false;
                item.folded = true;
            }

            saved_state.push((path, note_backup, items_backup));
        }
    }

    Ok(saved_state)
}

/// Restore decrypted state after save.
/// The cipher is kept valid since it was just written to disk.
pub fn restore_after_save(items: &mut [TodoItem], saved: &[SavedNodeState]) {
    for (path, note, children) in saved {
        if let Some(item) = navigate_mut(items, path) {
            item.note.clone_from(note);
            item.items.clone_from(children);
            item.unlocked = true;
            item.folded = false;
            // cipher stays valid — it matches the content we just saved
        }
    }
}

/// Invalidate the cipher cache for an encrypted ancestor.
/// Call this when any modification is made inside an unlocked encrypted subtree.
pub fn invalidate_cipher(item: &mut TodoItem) {
    if item.unlocked && item.cipher.is_some() {
        item.cipher = None;
    }
}

fn navigate_mut<'a>(items: &'a mut [TodoItem], path: &[usize]) -> Option<&'a mut TodoItem> {
    if path.is_empty() {
        return None;
    }
    let mut current = items.get_mut(path[0])?;
    for &idx in &path[1..] {
        current = current.items.get_mut(idx)?;
    }
    Some(current)
}

use std::io;
use std::path::PathBuf;
use thiserror::Error;

#[derive(Debug, Error)]
pub enum OmelaError {
    #[error("I/O error on {path}: {source}")]
    Io { path: PathBuf, source: io::Error },

    #[error("JSON error: {0}")]
    Json(#[from] serde_json::Error),

    #[error("YAML error: {0}")]
    Yaml(#[from] serde_yaml::Error),

    #[error("Invalid tree path: {0:?}")]
    InvalidPath(Vec<usize>),

    #[error("{0}")]
    Other(String),
}

impl OmelaError {
    pub fn io(path: impl Into<PathBuf>, source: io::Error) -> Self {
        Self::Io {
            path: path.into(),
            source,
        }
    }
}

pub type Result<T> = std::result::Result<T, OmelaError>;

use std::fs;
use std::path::{Path, PathBuf};

use crate::error::{OmelaError, Result};
use crate::model::TodoFile;
use crate::storage::TodoStorage;

const EXTENSION: &str = ".todo.json";

pub struct FileStorage {
    base_dir: PathBuf,
}

impl FileStorage {
    /// Create a new `FileStorage` rooted at the given directory.
    /// Creates the directory if it does not exist.
    ///
    /// # Errors
    /// Returns an error if the directory cannot be created.
    pub fn new(base_dir: impl Into<PathBuf>) -> Result<Self> {
        let base_dir = base_dir.into();
        fs::create_dir_all(&base_dir).map_err(|e| OmelaError::io(&base_dir, e))?;
        Ok(Self { base_dir })
    }

    fn file_path(&self, name: &str) -> PathBuf {
        self.base_dir.join(format!("{name}{EXTENSION}"))
    }
}

impl TodoStorage for FileStorage {
    fn list(&self) -> Result<Vec<String>> {
        let mut names = Vec::new();
        let entries = fs::read_dir(&self.base_dir).map_err(|e| OmelaError::io(&self.base_dir, e))?;
        for entry in entries {
            let entry = entry.map_err(|e| OmelaError::io(&self.base_dir, e))?;
            if let Some(name) = entry.file_name().to_str()
                && let Some(stem) = name.strip_suffix(EXTENSION)
            {
                names.push(stem.to_owned());
            }
        }
        names.sort();
        Ok(names)
    }

    fn load(&self, name: &str) -> Result<TodoFile> {
        let path = self.file_path(name);
        let content = fs::read_to_string(&path).map_err(|e| OmelaError::io(&path, e))?;
        let file: TodoFile = serde_json::from_str(&content)?;
        Ok(file)
    }

    fn save(&self, name: &str, file: &TodoFile) -> Result<()> {
        let path = self.file_path(name);
        let content = serde_json::to_string_pretty(file)?;
        fs::write(&path, content).map_err(|e| OmelaError::io(&path, e))?;
        Ok(())
    }

    fn delete(&self, name: &str) -> Result<()> {
        let path = self.file_path(name);
        fs::remove_file(&path).map_err(|e| OmelaError::io(&path, e))?;
        Ok(())
    }

    fn exists(&self, name: &str) -> Result<bool> {
        Ok(self.file_path(name).exists())
    }
}

/// Export a `TodoFile` as YAML string.
///
/// # Errors
/// Returns an error if serialization fails.
pub fn to_yaml(file: &TodoFile) -> Result<String> {
    Ok(serde_yaml::to_string(file)?)
}

/// Import a `TodoFile` from YAML string.
///
/// # Errors
/// Returns an error if the YAML is invalid.
pub fn from_yaml(content: &str) -> Result<TodoFile> {
    Ok(serde_yaml::from_str(content)?)
}

/// Import a `TodoFile` from JSON string.
///
/// # Errors
/// Returns an error if the JSON is invalid.
pub fn from_json(content: &str) -> Result<TodoFile> {
    Ok(serde_json::from_str(content)?)
}

/// Detect format and import: tries JSON first, falls back to YAML.
///
/// # Errors
/// Returns an error if neither JSON nor YAML parsing succeeds.
pub fn from_auto(content: &str) -> Result<TodoFile> {
    from_json(content).or_else(|_| from_yaml(content))
}

/// Load a `TodoFile` from an arbitrary path (auto-detecting format).
///
/// # Errors
/// Returns an error if the file cannot be read or parsed.
pub fn load_path(path: &Path) -> Result<TodoFile> {
    let content = fs::read_to_string(path).map_err(|e| OmelaError::io(path, e))?;
    from_auto(&content)
}

#[cfg(test)]
#[allow(clippy::expect_used)]
mod tests {
    use super::*;
    use crate::model::TodoItem;

    fn make_test_file() -> TodoFile {
        let mut file = TodoFile::new("test-project");
        let mut task = TodoItem::new("Task 1");
        task.important = true;
        task.note = "Some **markdown** note".to_owned();
        task.items.push(TodoItem::new("Subtask 1.1"));
        file.items.push(task);
        file
    }

    #[test]
    fn file_storage_round_trip() {
        let dir = tempfile::tempdir().expect("tempdir");
        let storage = FileStorage::new(dir.path()).expect("new");

        let file = make_test_file();
        storage.save("myproject", &file).expect("save");

        assert!(storage.exists("myproject").expect("exists"));

        let loaded = storage.load("myproject").expect("load");
        assert_eq!(loaded.title, "test-project");
        assert_eq!(loaded.items.len(), 1);
        assert!(loaded.items[0].important);
        assert_eq!(loaded.items[0].items[0].title, "Subtask 1.1");

        let names = storage.list().expect("list");
        assert_eq!(names, vec!["myproject"]);

        storage.delete("myproject").expect("delete");
        assert!(!storage.exists("myproject").expect("exists after delete"));
    }

    #[test]
    fn yaml_round_trip() {
        let file = make_test_file();
        let yaml = to_yaml(&file).expect("to_yaml");
        let parsed = from_yaml(&yaml).expect("from_yaml");
        assert_eq!(parsed.title, file.title);
        assert_eq!(parsed.items.len(), file.items.len());
    }

    #[test]
    fn auto_detect_json() {
        let file = make_test_file();
        let json = serde_json::to_string_pretty(&file).expect("json");
        let parsed = from_auto(&json).expect("auto json");
        assert_eq!(parsed.title, "test-project");
    }

    #[test]
    fn auto_detect_yaml() {
        let file = make_test_file();
        let yaml = to_yaml(&file).expect("yaml");
        let parsed = from_auto(&yaml).expect("auto yaml");
        assert_eq!(parsed.title, "test-project");
    }

    #[test]
    fn load_path_json() {
        let dir = tempfile::tempdir().expect("tempdir");
        let path = dir.path().join("test.json");
        let file = make_test_file();
        fs::write(&path, serde_json::to_string_pretty(&file).expect("json")).expect("write");
        let loaded = load_path(&path).expect("load_path");
        assert_eq!(loaded.title, "test-project");
    }
}

use crate::model::TodoItem;
use crate::tree_ops::TreePath;

/// Options controlling filter behavior.
#[derive(Debug, Default, Clone)]
pub struct FilterOptions {
    /// Include note content in search.
    pub search_notes: bool,
    /// Use case-sensitive matching.
    pub case_sensitive: bool,
}

/// Filter items in a tree, returning paths of all matching items.
///
/// An item matches if its title (and optionally note) contains the query.
/// Parent items of matches are included to preserve tree structure.
#[must_use]
pub fn filter_items(items: &[TodoItem], query: &str, options: &FilterOptions) -> Vec<TreePath> {
    let mut matches = Vec::new();
    let mut path = Vec::new();
    for (i, item) in items.iter().enumerate() {
        path.push(i);
        collect_matches(item, query, options, &mut path, &mut matches);
        path.pop();
    }
    matches
}

fn matches_query(item: &TodoItem, query: &str, options: &FilterOptions) -> bool {
    if options.case_sensitive {
        if item.title.contains(query) {
            return true;
        }
        if options.search_notes && item.note.contains(query) {
            return true;
        }
    } else {
        let q = query.to_lowercase();
        if item.title.to_lowercase().contains(&q) {
            return true;
        }
        if options.search_notes && item.note.to_lowercase().contains(&q) {
            return true;
        }
    }
    false
}

fn collect_matches(
    item: &TodoItem,
    query: &str,
    options: &FilterOptions,
    path: &mut TreePath,
    results: &mut Vec<TreePath>,
) -> bool {
    let self_matches = matches_query(item, query, options);
    let mut child_matches = false;

    for (i, child) in item.items.iter().enumerate() {
        path.push(i);
        if collect_matches(child, query, options, path, results) {
            child_matches = true;
        }
        path.pop();
    }

    if self_matches || child_matches {
        results.push(path.clone());
        true
    } else {
        false
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::model::TodoItem;

    fn make_tree() -> Vec<TodoItem> {
        let mut parent = TodoItem::new("Project Alpha");
        parent.note = "Main project notes".to_owned();

        let mut child1 = TodoItem::new("Design API");
        child1.note = "REST endpoints".to_owned();
        child1.items.push(TodoItem::new("Define schemas"));

        let child2 = TodoItem::new("Write tests");

        parent.items.push(child1);
        parent.items.push(child2);

        let other = TodoItem::new("Beta release");
        vec![parent, other]
    }

    #[test]
    fn filter_by_title() {
        let items = make_tree();
        let opts = FilterOptions::default();
        let matches = filter_items(&items, "design", &opts);
        assert!(matches.contains(&vec![0, 0]));
        assert!(matches.contains(&vec![0])); // parent included
    }

    #[test]
    fn filter_case_sensitive() {
        let items = make_tree();
        let opts = FilterOptions {
            case_sensitive: true,
            search_notes: false,
        };
        let matches = filter_items(&items, "design", &opts);
        assert!(matches.is_empty());

        let matches = filter_items(&items, "Design", &opts);
        assert!(matches.contains(&vec![0, 0]));
    }

    #[test]
    fn filter_includes_notes() {
        let items = make_tree();
        let opts = FilterOptions {
            search_notes: true,
            case_sensitive: false,
        };
        let matches = filter_items(&items, "rest endpoints", &opts);
        assert!(matches.contains(&vec![0, 0]));
    }

    #[test]
    fn filter_no_match() {
        let items = make_tree();
        let opts = FilterOptions::default();
        let matches = filter_items(&items, "nonexistent", &opts);
        assert!(matches.is_empty());
    }

    #[test]
    fn filter_parent_included_for_deep_match() {
        let items = make_tree();
        let opts = FilterOptions::default();
        let matches = filter_items(&items, "schemas", &opts);
        // "Define schemas" is at [0, 0, 0], parent [0, 0] and grandparent [0] included
        assert!(matches.contains(&vec![0, 0, 0]));
        assert!(matches.contains(&vec![0, 0]));
        assert!(matches.contains(&vec![0]));
    }

    #[test]
    fn filter_top_level_match() {
        let items = make_tree();
        let opts = FilterOptions::default();
        let matches = filter_items(&items, "beta", &opts);
        assert!(matches.contains(&vec![1]));
        assert!(!matches.contains(&vec![0]));
    }
}

