        add_child(&mut file, &vec![0], TodoItem::new("A3")).expect("ok");
        assert_eq!(file.items[0].items.len(), 3);
        assert_eq!(file.items[0].items[2].title, "A3");
    }

    // -- remove_item --

    #[test]
