/// Render the `:help` overlay.
pub fn render_help(frame: &mut ratatui::Frame, area: Rect, scroll: u16) {
    let popup = centered_rect(80, 90, area);
    frame.render_widget(Clear, popup);

    let lines: Vec<Line<'_>> = HELP_TEXT
        .lines()
        .filter_map(|line| {
            // Skip separator rows
            if line.starts_with('|') && line.contains("---") {
                return None;
            }
            Some(render_help_line(line))
        })
        .collect();

    let block = Block::default()
        .title(" Help — :help (↑↓ scroll, q/Esc close) ")
        .borders(Borders::ALL)
        .border_style(Style::default().fg(Color::LightCyan));

    let paragraph = Paragraph::new(lines)
        .block(block)
        .wrap(Wrap { trim: false })
        .scroll((scroll, 0));
    frame.render_widget(paragraph, popup);
}

const fn centered_rect(pct_x: u16, pct_y: u16, area: Rect) -> Rect {
    let w = area.width * pct_x / 100;
    let h = area.height * pct_y / 100;
    let x = area.x + (area.width.saturating_sub(w)) / 2;
    let y = area.y + (area.height.saturating_sub(h)) / 2;
    Rect::new(x, y, w, h)
}

fn render_help_line(line: &str) -> Line<'_> {
    if let Some(h) = line.strip_prefix("### ") {
        return Line::styled(h, Style::default().fg(Color::Yellow).add_modifier(Modifier::BOLD));
    }
    if let Some(h) = line.strip_prefix("## ") {
        return Line::from(vec![
            Span::raw(""),
            Span::styled(h, Style::default().fg(Color::LightCyan).add_modifier(Modifier::BOLD)),
        ]);
    }
    if let Some(h) = line.strip_prefix("# ") {
        return Line::styled(
            h,
            Style::default()
                .fg(Color::LightCyan)
                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED),
        );
    }
    if line.starts_with('|') {
        return render_table_row(line);
    }
    render_inline_markup(line)
}

fn render_table_row(line: &str) -> Line<'_> {
    let cells: Vec<&str> = line.split('|').collect();
    // cells[0] is empty (before first |), cells[1] is key, cells[2] is action
    if cells.len() >= 3 {
        let key = cells[1].trim();
        let action = cells[2].trim();
        let key_width = 22;
        Line::from(vec![
            Span::styled(format!("  {key:<key_width$}"), Style::default().fg(Color::Green)),
            Span::raw(action.to_owned()),
        ])
    } else {
        Line::raw(line)
    }
}

fn render_inline_markup(line: &str) -> Line<'_> {
    let mut spans = Vec::new();
    let mut rest = line;

    while let Some(pos) = rest.find('`') {
        if pos > 0 {
            spans.push(Span::raw(&rest[..pos]));
        }
        let after = &rest[pos + 1..];
        if let Some(end) = after.find('`') {
            spans.push(Span::styled(&after[..end], Style::default().fg(Color::Green)));
            rest = &after[end + 1..];
        } else {
            spans.push(Span::raw(&rest[pos..]));
            rest = "";
            break;
        }
    }
    if !rest.is_empty() {
        spans.push(Span::raw(rest));
    }
    Line::from(spans)
}

use crossterm::event::{self, Event, KeyCode, KeyEvent, KeyModifiers};

use crate::app::{App, Focus};

/// Handle a key event, returning true if the app should repaint.
pub fn handle_key(app: &mut App, key: KeyEvent) -> bool {
    // Command mode
    if app.command_active {
        return handle_command_key(app, key);
    }

    // Filter mode input
    if app.filter_active {
        return handle_filter_key(app, key);
    }

    // Title editing mode
    if app.editing_title {
        return handle_edit_key(app, key);
    }

    // Normal mode
    match app.focus {
        Focus::Tree => handle_tree_key(app, key),
        Focus::Note => handle_note_key(app, key),
    }
}

#[allow(clippy::too_many_lines)]
fn handle_tree_key(app: &mut App, key: KeyEvent) -> bool {
    let shift = key.modifiers.contains(KeyModifiers::SHIFT);
    let ctrl = key.modifiers.contains(KeyModifiers::CONTROL);

    // Clear pending delete on any key except 'y' (confirm)
    if app.pending_delete && key.code != KeyCode::Char('y') {
        app.pending_delete = false;
        app.status_message.clear();
    }

    // Shift+Arrow or HJKL: move items
    if shift && !ctrl {
        return match key.code {
            KeyCode::Up => {
                app.swap_up();
                true
            }
            KeyCode::Down => {
                app.swap_down();
                true
            }
            KeyCode::Left => {
                app.promote();
                true
            }
            KeyCode::Right => {
                app.demote();
                true
            }
            _ => false,
        };
    }

    match (key.code, ctrl) {
        (KeyCode::Char('q'), false) => {
            app.should_quit = true;
            true
        }
        (KeyCode::Up, false) => {
            app.move_up();
            true
        }
        (KeyCode::Down, false) => {
            app.move_down();
            true
        }
        (KeyCode::Left, false) => {
            app.collapse_current();
            true
        }
        (KeyCode::Right, false) => {
            app.expand_current();
            true
        }
        (KeyCode::Char(' '), false) => {
            app.toggle_completed();
            true
        }
        (KeyCode::Enter, false) => {
            app.start_editing();
            true
        }
        (KeyCode::Char('n'), false) => {
            app.new_sibling();
            true
        }
        (KeyCode::Char('b'), false) => {
            app.new_child();
            true
        }
        (KeyCode::Char('d'), false) => {
            app.delete_current();
            true
        }
        (KeyCode::Char('y'), false) if app.pending_delete => {
            app.pending_delete = false;
            app.force_delete_current();
            true
        }
        (KeyCode::Char('!'), false) => {
            app.toggle_important();
            true
        }
        (KeyCode::Char('K'), false) => {
            app.swap_up();
            true
        }
        (KeyCode::Char('J'), false) => {
            app.swap_down();
            true
        }
        (KeyCode::Char('H'), false) => {
            app.promote();
            true
        }
        (KeyCode::Char('L'), false) => {
            app.demote();
            true
        }
        (KeyCode::Char('s'), true) => {
            // Save handled in main loop
            true
        }
        (KeyCode::Tab, false) => {
            app.load_editor();
            app.focus = Focus::Note;
            true
        }
        (KeyCode::Char('/'), false) => {
            app.filter_active = true;
            app.filter_saved = app.filter_text.clone();
            // Keep current filter text for editing
            true
        }
        (KeyCode::Char(':'), false) => {
            app.command_active = true;
            app.command_buffer.clear();
            app.completer.update("");
            true
        }
        (KeyCode::F(1), false) => {
            app.show_help = true;
            app.help_scroll = 0;
            true
        }
        (KeyCode::Char(']'), false) => {
            app.note_panel_pct = (app.note_panel_pct + 5).min(80);
            true
        }
        (KeyCode::Char('['), false) => {
            app.note_panel_pct = app.note_panel_pct.saturating_sub(5).max(20);
            true
        }
        (KeyCode::Char('S'), false) => {
            app.sort_children();
            true
        }
        (KeyCode::Char('c'), false) => {
            app.clone_subtree();
            true
        }
        _ => false,
    }
}

fn handle_note_key(app: &mut App, key: KeyEvent) -> bool {
    // Tab in normal mode returns to tree
    if let Some(editor) = &app.editor
        && editor.mode == crate::note_editor::EditorMode::Normal
        && key.code == KeyCode::Tab
    {
        app.save_editor();
        app.focus = Focus::Tree;
        return true;
    }

    app.editor.as_mut().is_some_and(|editor| editor.handle_key(key))
}

fn handle_edit_key(app: &mut App, key: KeyEvent) -> bool {
    match key.code {
        KeyCode::Enter => {
            app.finish_editing();
            true
        }
        KeyCode::Esc => {
            app.cancel_editing();
            true
        }
        KeyCode::Left => {
            app.edit_select_all = false;
            if app.edit_cursor > 0 {
                app.edit_cursor -= 1;
            }
            true
        }
        KeyCode::Right => {
            app.edit_select_all = false;
            if app.edit_cursor < app.edit_buffer.len() {
                app.edit_cursor += 1;
            }
            true
        }
        KeyCode::Home => {
            app.edit_select_all = false;
            app.edit_cursor = 0;
            true
        }
        KeyCode::End => {
            app.edit_select_all = false;
            app.edit_cursor = app.edit_buffer.len();
            true
        }
        KeyCode::Backspace => {
            if app.edit_select_all {
                app.edit_buffer.clear();
                app.edit_cursor = 0;
                app.edit_select_all = false;
            } else if app.edit_cursor > 0 {
                app.edit_buffer.remove(app.edit_cursor - 1);
                app.edit_cursor -= 1;
            }
            true
        }
        KeyCode::Delete => {
            if app.edit_select_all {
                app.edit_buffer.clear();
                app.edit_cursor = 0;
                app.edit_select_all = false;
            } else if app.edit_cursor < app.edit_buffer.len() {
                app.edit_buffer.remove(app.edit_cursor);
            }
            true
        }
        KeyCode::Char(c) => {
            if app.edit_select_all {
                app.edit_buffer.clear();
                app.edit_cursor = 0;
                app.edit_select_all = false;
            }
            app.edit_buffer.insert(app.edit_cursor, c);
            app.edit_cursor += 1;
            true
        }
        _ => false,
    }
}

fn handle_filter_key(app: &mut App, key: KeyEvent) -> bool {
    match key.code {
        KeyCode::Esc => {
            // Revert to saved filter state
            app.filter_active = false;
            app.filter_text.clone_from(&app.filter_saved);
            if app.filter_text.is_empty() {
                app.filter_exclude = false;
                app.status_message.clear();
                app.rebuild_rows();
            } else {
                app.apply_filter();
            }
            true
        }
        KeyCode::Enter => {
            app.filter_active = false;
            if let Some(rest) = app.filter_text.strip_prefix('!') {
                app.filter_exclude = true;
                app.filter_text = rest.to_owned();
            } else {
                app.filter_exclude = false;
            }
            if app.filter_text.is_empty() {
                app.status_message.clear();
                app.rebuild_rows();
            } else {
                app.apply_filter();
            }
            true
        }
        KeyCode::Backspace => {
            app.filter_text.pop();
            app.apply_filter_live();
            true
        }
        KeyCode::Char(c) => {
            app.filter_text.push(c);
            app.apply_filter_live();
            true
        }
        _ => false,
    }
}

/// Returns true if the command needs storage access (`execute_command` should be called).
fn handle_command_key(app: &mut App, key: KeyEvent) -> bool {
    match key.code {
        KeyCode::Esc => {
            app.command_active = false;
            app.command_buffer.clear();
            app.command_history_index = None;
            app.completer.matches.clear();
            true
        }
        KeyCode::Enter => {
            let cmd = app.command_buffer.trim().to_owned();
            if !cmd.is_empty() {
                app.command_history.push(cmd);
            }
            app.command_history_index = None;
            app.completer.matches.clear();
            true
        }
        KeyCode::Tab => {
            app.completer.update(&app.command_buffer);
            if let Some(completion) = app.completer.next() {
                app.command_buffer = completion.to_owned();
            }
            true
        }
        KeyCode::BackTab => {
            app.completer.update(&app.command_buffer);
            if let Some(completion) = app.completer.prev() {
                app.command_buffer = completion.to_owned();
            }
            true
        }
        KeyCode::Up => {
            if !app.command_history.is_empty() {
                let idx = app
                    .command_history_index
                    .map_or(app.command_history.len() - 1, |i| i.saturating_sub(1));
                app.command_history_index = Some(idx);
                app.command_buffer.clone_from(&app.command_history[idx]);
                app.completer.update(&app.command_buffer);
            }
            true
        }
        KeyCode::Down => {
            if let Some(idx) = app.command_history_index {
                if idx + 1 < app.command_history.len() {
                    app.command_history_index = Some(idx + 1);
                    app.command_buffer.clone_from(&app.command_history[idx + 1]);
                } else {
                    app.command_history_index = None;
                    app.command_buffer.clear();
                }
            }
            app.completer.update(&app.command_buffer);
            true
        }
        KeyCode::Backspace => {
            if app.command_buffer.is_empty() {
                app.command_active = false;
                app.command_history_index = None;
                app.completer.matches.clear();
            } else {
                app.command_buffer.pop();
                app.completer.update(&app.command_buffer);
                app.completer.reset_selection();
            }
            true
        }
        KeyCode::Char(c) => {
            app.command_history_index = None;
            app.command_buffer.push(c);
            app.completer.update(&app.command_buffer);
            app.completer.reset_selection();
            true
        }
        _ => false,
    }
}

/// Poll for the next event with a timeout.
///
/// # Errors
/// Returns an error if event polling fails.
pub fn poll_event(timeout: std::time::Duration) -> std::io::Result<Option<Event>> {
    if event::poll(timeout)? {
        Ok(Some(event::read()?))
    } else {
        Ok(None)
    }
}

