#[derive(Parser)]
#[command(name = "duir", about = "Hierarchical todo tree manager")]
struct Cli {
    /// Directory containing .todo.json files
    #[arg(short, long)]
    dir: Option<PathBuf>,

    /// Specific files to open
    files: Vec<PathBuf>,
}

fn main() -> io::Result<()> {
    let cli = Cli::parse();
    let config = duir_core::config::Config::load();

    let storage_dir = cli.dir.clone().unwrap_or_else(|| config.storage.central.clone());

    let mut app = App::new();
    app.autosave_global = config.editor.autosave;
    app.note_panel_pct = config.ui.note_panel_pct;

    if cli.files.is_empty() {
        // Load from all configured storage dirs
        for dir in &config.storage_dirs() {
            if let Ok(storage) = FileStorage::new(dir)
                && let Ok(names) = storage.list()
            {
                for name in &names {
                    match storage.load(name) {
                        Ok(data) => app.add_file(name.clone(), data),
                        Err(e) => eprintln!("Error loading {name}: {e}"),
                    }
                }
            }
        }
    } else {
        for path in &cli.files {
            match duir_core::file_storage::load_path(path) {
                Ok(data) => {
                    let name = path
                        .file_stem()
                        .and_then(|s| s.to_str())
                        .unwrap_or("untitled")
                        .to_owned();
                    app.add_file(name, data);
                }
                Err(e) => eprintln!("Error loading {}: {e}", path.display()),
            }
        }
    }

    let first_run = app.files.is_empty();
    if first_run {
        app.add_empty_file("todo");
    }

    // Initialize editor for the first item
    app.load_editor();

    if first_run {
        app.show_about = true;
    }

    enable_raw_mode()?;
    let mut stdout = io::stdout();
    execute!(stdout, EnterAlternateScreen)?;
    let backend = CrosstermBackend::new(stdout);
    let mut terminal = Terminal::new(backend)?;

    let result = run_loop(&mut terminal, &mut app, &storage_dir, &config);

    disable_raw_mode()?;
    execute!(terminal.backend_mut(), LeaveAlternateScreen)?;
    terminal.show_cursor()?;

    result
}

#[allow(clippy::too_many_lines)]
fn run_loop(
    terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
    app: &mut App,
    storage_dir: &PathBuf,
    config: &duir_core::config::Config,
) -> io::Result<()> {
    let mut last_save = std::time::Instant::now();
    let autosave_interval = config.editor.autosave_interval_secs;
    loop {
        terminal.draw(|frame| {
            let size = frame.area();

            let main_chunks = Layout::default()
                .direction(Direction::Vertical)
                .constraints([Constraint::Min(3), Constraint::Length(1)])
                .split(size);

            let content_chunks = Layout::default()
                .direction(Direction::Horizontal)
                .constraints([
                    Constraint::Percentage(100 - app.note_panel_pct),
                    Constraint::Percentage(app.note_panel_pct),
                ])
                .split(main_chunks[0]);

            // Tree pane
            let tree_title = match (app.has_unsaved(), !app.filter_text.is_empty() && !app.filter_active) {
                (true, true) => format!(" Tree (*) [/{}] ", app.filter_text),
                (true, false) => " Tree (*) ".to_owned(),
                (false, true) => format!(" Tree [/{}] ", app.filter_text),
                (false, false) => " Tree ".to_owned(),
            };
            let tree_border_style = if app.focus == Focus::Tree {
                Style::default().add_modifier(Modifier::BOLD)
            } else {
                Style::default()
            };
            let tree_block = Block::default()
                .title(tree_title)
                .borders(Borders::ALL)
                .border_style(tree_border_style);
            frame.render_stateful_widget(TreeView::new().block(tree_block), content_chunks[0], app);

            // Note pane
            let focused = app.focus == Focus::Note;
            if let Some(editor) = &mut app.editor {
                let has_cmdline = matches!(
                    editor.mode,
                    crate::note_editor::EditorMode::Command | crate::note_editor::EditorMode::Search
                );
                if has_cmdline {
                    let note_chunks = Layout::default()
                        .direction(Direction::Vertical)
                        .constraints([Constraint::Min(3), Constraint::Length(1)])
                        .split(content_chunks[1]);
                    editor.set_block(" Note", focused);
                    editor.render(frame, note_chunks[0]);
                    let cmd_line = editor.status_line();
                    frame.render_widget(Paragraph::new(cmd_line), note_chunks[1]);
                } else {
                    editor.set_block(" Note", focused);
                    editor.render(frame, content_chunks[1]);
                }
            } else {
                let note_content = app.current_note();
                let note_border_style = if focused {
                    Style::default().add_modifier(Modifier::BOLD)
                } else {
                    Style::default()
                };
                let note_block = Block::default()
                    .title(" Note ")
                    .borders(Borders::ALL)
                    .border_style(note_border_style);
                let note_widget = NoteView::new(&note_content).block(note_block).scroll(0);
                frame.render_widget(note_widget, content_chunks[1]);
            }

            // Status bar
            let status = build_status_line(app);
            frame.render_widget(Paragraph::new(status), main_chunks[1]);

            // Command palette popup (above status bar)
            if app.command_active && !app.completer.matches.is_empty() {
                render_palette(frame, &app.completer, main_chunks[1]);
            }

            // Overlays
            if app.show_about {
                help::render_about(frame, size);
            }
            if app.show_help {
                help::render_help(frame, size, app.help_scroll);
            }
            if let Some(prompt) = &app.password_prompt {
                prompt.render(frame, size);
            }
        })?;

        // Process pending crypto after redraw (so "Working..." is visible)
        if let Some((password, action)) = app.pending_crypto.take() {
            app.handle_password_result(&password, action);
        }

        // Block for input, with timeout only for autosave
        let has_pending_save = app.focus == Focus::Tree && app.files.iter().any(|f| f.autosave && f.modified);
        let timeout = if app.pending_crypto.is_some() {
            Duration::from_millis(1) // process crypto immediately
        } else if has_pending_save {
            Duration::from_secs(autosave_interval)
        } else {
            Duration::from_secs(3600) // effectively block
        };
        if let Some(Event::Key(key)) = input::poll_event(timeout)? {
            // Handle overlay input first
            if let Some(prompt) = &mut app.password_prompt {
                match prompt.handle_key(key) {
                    crate::password::PromptResult::Submitted(password) => {
                        if let Some(prompt) = app.password_prompt.take() {
                            app.pending_crypto = Some((password, prompt.callback));
                        }
                        app.set_status("⏳ Working...", app::StatusLevel::Warning);
                        continue;
                    }
                    crate::password::PromptResult::Cancelled => {
                        app.password_prompt = None;
                    }
                    crate::password::PromptResult::Pending => {}
                }
                continue;
            }
            if app.show_about {
                app.show_about = false;
                continue;
            }
            if app.show_help {
                match key.code {
                    KeyCode::Esc | KeyCode::Char('q') => app.show_help = false,
                    KeyCode::Down | KeyCode::Char('j') => app.help_scroll += 1,
                    KeyCode::Up | KeyCode::Char('k') => {
                        app.help_scroll = app.help_scroll.saturating_sub(1);
                    }
                    KeyCode::PageDown => app.help_scroll += 20,
                    KeyCode::PageUp => app.help_scroll = app.help_scroll.saturating_sub(20),
                    _ => {}
                }
                continue;
            }

            if key.code == KeyCode::Char('s')
                && key.modifiers.contains(KeyModifiers::CONTROL)
                && !app.editing_title
                && !app.filter_active
                && !app.command_active
            {
                if let Ok(storage) = FileStorage::new(storage_dir) {
                    app.save_all(&storage);
                }
            } else if app.command_active && key.code == KeyCode::Enter {
                // Execute command with storage access
                if let Ok(storage) = FileStorage::new(storage_dir) {
                    app.execute_command(&storage);
                }
            } else {
                input::handle_key(app, key);
            }
        }

        // Autosave — fires when poll timeout expires (no input for autosave_interval)
        if app.focus == Focus::Tree
            && last_save.elapsed() >= Duration::from_secs(autosave_interval)
            && app.files.iter().any(|f| f.autosave && f.modified)
            && let Ok(storage) = FileStorage::new(storage_dir)
        {
            app.save_all(&storage);
            last_save = std::time::Instant::now();
        }

        if app.should_quit {
            break;
        }
    }
    Ok(())
}

fn render_palette(frame: &mut ratatui::Frame, completer: &crate::completer::Completer, status_area: Rect) {
    use ratatui::widgets::Clear;

    let matches = &completer.matches;
    let max_visible = 10.min(matches.len());
    #[allow(clippy::cast_possible_truncation)]
    let height = max_visible as u16;

    // Position popup just above the status bar
    let popup = Rect::new(
        status_area.x + 1,
        status_area.y.saturating_sub(height),
        30.min(status_area.width),
        height,
    );

    frame.render_widget(Clear, popup);

    let lines: Vec<Line<'_>> = matches
        .iter()
        .take(max_visible)
        .enumerate()
        .map(|(i, cmd)| {
            let style = if completer.selected == Some(i) {
                Style::default().bg(Color::DarkGray).fg(Color::Yellow)
            } else {
                Style::default().fg(Color::White).bg(Color::Rgb(30, 30, 30))
            };
            Line::styled(format!(" {cmd}"), style)
        })
        .collect();

    let block = Block::default().borders(Borders::NONE);
    let paragraph = Paragraph::new(lines).block(block);
    frame.render_widget(paragraph, popup);
}
fn build_status_line(app: &App) -> Line<'_> {
    if app.command_active {
        Line::from(vec![
            Span::raw(":"),
            Span::styled(
                format!("{}▏", app.command_buffer),
                Style::default().add_modifier(Modifier::BOLD),
            ),
        ])
    } else if app.filter_active {
        Line::from(vec![
            Span::raw("Filter: "),
            Span::styled(
                format!("{}▏", app.filter_text),
                Style::default().add_modifier(Modifier::BOLD),
            ),
            Span::raw("  [Enter] apply  [Esc] cancel"),
        ])
    } else if app.editing_title {
        Line::from(vec![
            Span::raw("Editing: "),
            Span::styled(
                "[Enter] confirm  [Esc] cancel",
                Style::default().add_modifier(Modifier::DIM),
            ),
        ])
    } else {
        let bold = Style::default().add_modifier(Modifier::BOLD);
        let mut spans = vec![
            Span::styled(" q", bold),
            Span::raw("uit "),
            Span::styled("n", bold),
            Span::raw("ew "),
            Span::styled("b", bold),
            Span::raw("ranch "),
            Span::styled("d", bold),
            Span::raw("el "),
            Span::styled("c", bold),
            Span::raw("lone "),
            Span::styled("!", bold),
            Span::raw("imp "),
            Span::styled("HJKL", bold),
            Span::raw(" move "),
            Span::styled("S", bold),
            Span::raw("ort "),
            Span::styled("/", bold),
            Span::raw("filter "),
            Span::styled("^S", bold),
            Span::raw("ave "),
            Span::styled("Tab", bold),
            Span::raw(" note "),
            Span::styled(":", bold),
            Span::raw("cmd "),
            Span::styled(":help", bold),
        ];
        if !app.status_message.is_empty() {
            let color = match app.status_level {
                app::StatusLevel::Info => Color::DarkGray,
                app::StatusLevel::Success => Color::Green,
                app::StatusLevel::Warning => Color::Yellow,
                app::StatusLevel::Error => Color::Red,
            };
            spans.push(Span::styled(
                format!("  │ {}", app.status_message),
                Style::default().fg(color),
            ));
        }
        Line::from(spans)
    }
}

#[cfg(test)]
#[allow(clippy::unwrap_used)]
mod tests {
    use super::*;
    use app::{App, Focus, StatusLevel};
    use duir_core::TodoStorage;
    use duir_core::model::{Completion, TodoFile, TodoItem};

    fn make_app_with_tree() -> App {
        let mut app = App::new();
        let mut file = TodoFile::new("test");
        let mut branch1 = TodoItem::new("Branch 1");
        branch1.note = "branch1 note".to_owned();
        let mut child11 = TodoItem::new("Child 1.1");
        child11.completed = Completion::Done;
        child11.note = "child11 note".to_owned();
        let mut child12 = TodoItem::new("Child 1.2");
        child12.important = true;
        child12.note = "child12 note".to_owned();
        branch1.items.push(child11);
        branch1.items.push(child12);
        let mut branch2 = TodoItem::new("Branch 2");
        branch2.note = "branch2 note".to_owned();
        branch2.items.push(TodoItem::new("Child 2.1"));
        file.items.push(branch1);
        file.items.push(branch2);
        file.items.push(TodoItem::new("Branch 3"));
        app.add_file("test".to_owned(), file);
        app
    }

    #[test]
    fn tab_into_note_loads_editor() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.load_editor();
        app.focus = Focus::Note;
        assert!(app.editor.is_some());
        assert_eq!(app.editor.as_ref().unwrap().content(), "branch1 note");
    }

    #[test]
    fn tab_back_saves_editor_to_model() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.load_editor();
        if let Some(editor) = &mut app.editor {
            editor.textarea.insert_str("MODIFIED");
            editor.dirty = true;
        }
        app.save_editor();
        assert!(app.files[0].data.items[0].note.contains("MODIFIED"));
    }

    #[test]
    fn editor_not_written_without_save() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.load_editor();
        if let Some(editor) = &mut app.editor {
            editor.textarea.insert_str("SHOULD NOT PERSIST");
        }
        assert_eq!(app.files[0].data.items[0].note, "branch1 note");
    }

    #[test]
    fn cursor_move_does_not_affect_model() {
        let mut app = make_app_with_tree();
        let original = app.files[0].data.items[0].note.clone();
        app.move_down();
        app.move_down();
        app.move_up();
        assert_eq!(app.files[0].data.items[0].note, original);
    }

    #[test]
    fn clone_then_navigate_correct_items() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.clone_subtree();
        assert_eq!(app.files[0].data.items[0].title, "Branch 1");
        assert_eq!(app.files[0].data.items[1].title, "Branch 1");
        assert_eq!(app.files[0].data.items[2].title, "Branch 2");
        assert_eq!(app.files[0].data.items[3].title, "Branch 3");
    }

    #[test]
    fn encrypt_sets_prompt() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.cmd_encrypt();
        assert!(app.password_prompt.is_some());
    }

    #[test]
    fn encrypt_then_decrypt_roundtrip() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.cmd_encrypt();
        {
            let cb = app.password_prompt.take().unwrap().callback;
            app.handle_password_result("pass", cb);
        }
        assert!(app.files[0].data.items[0].cipher.is_some());
        assert!(app.files[0].data.items[0].items.is_empty());

        app.cursor = 1;
        app.expand_current();
        {
            let cb = app.password_prompt.take().unwrap().callback;
            app.handle_password_result("pass", cb);
        }
        assert!(app.files[0].data.items[0].unlocked);
        assert_eq!(app.files[0].data.items[0].items.len(), 2);
        assert_eq!(app.files[0].data.items[0].note, "branch1 note");
    }

    /// Tests the EXACT code path used in the real app:
    /// prompt → stash (password, callback) → process on next iteration.
    /// This is the path that broke TWICE due to callback being lost.
    #[test]
    fn encrypt_decrypt_via_pending_crypto_path() {
        let mut app = make_app_with_tree();
        app.cursor = 1;

        // Encrypt via pending_crypto (real app path)
        app.cmd_encrypt();
        assert!(app.password_prompt.is_some());
        let prompt = app.password_prompt.take().unwrap();
        app.pending_crypto = Some(("pass".to_owned(), prompt.callback));
        // Simulate: next iteration processes pending_crypto
        let (pw, action) = app.pending_crypto.take().unwrap();
        app.handle_password_result(&pw, action);

        assert!(app.files[0].data.items[0].cipher.is_some());
        assert!(app.files[0].data.items[0].items.is_empty());

        // Decrypt via pending_crypto (real app path)
        app.cursor = 1;
        app.expand_current();
        assert!(app.password_prompt.is_some());
        let prompt = app.password_prompt.take().unwrap();
        app.pending_crypto = Some(("pass".to_owned(), prompt.callback));
        let (pw, action) = app.pending_crypto.take().unwrap();
        app.handle_password_result(&pw, action);

        assert!(app.files[0].data.items[0].unlocked);
        assert_eq!(app.files[0].data.items[0].items.len(), 2);
        assert_eq!(app.files[0].data.items[0].note, "branch1 note");
    }

    #[test]
    fn decrypt_wrong_password_no_corruption() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.cmd_encrypt();
        {
            let cb = app.password_prompt.take().unwrap().callback;
            app.handle_password_result("correct", cb);
        }
        let cipher = app.files[0].data.items[0].cipher.clone();

        app.cursor = 1;
        app.expand_current();
        {
            let cb = app.password_prompt.take().unwrap().callback;
            app.handle_password_result("wrong", cb);
        }
        assert_eq!(app.files[0].data.items[0].cipher, cipher);
        assert!(app.files[0].data.items[0].items.is_empty());
        assert_eq!(app.status_level, StatusLevel::Error);
    }

    #[test]
    fn collapse_encrypted_relocks() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.cmd_encrypt();
        {
            let cb = app.password_prompt.take().unwrap().callback;
            app.handle_password_result("pass", cb);
        }
        app.cursor = 1;
        app.expand_current();
        {
            let cb = app.password_prompt.take().unwrap().callback;
            app.handle_password_result("pass", cb);
        }
        assert!(app.files[0].data.items[0].unlocked);

        app.cursor = 1;
        app.collapse_current();
        assert!(!app.files[0].data.items[0].unlocked);
        assert!(app.files[0].data.items[0].items.is_empty());
    }

    #[test]
    fn decrypt_requires_unlock() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.cmd_encrypt();
        {
            let cb = app.password_prompt.take().unwrap().callback;
            app.handle_password_result("pass", cb);
        }
        app.cmd_decrypt();
        assert_eq!(app.status_level, StatusLevel::Warning);
        assert!(app.files[0].data.items[0].cipher.is_some());
    }

    #[test]
    fn save_reencrypts_unlocked() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.cmd_encrypt();
        {
            let cb = app.password_prompt.take().unwrap().callback;
            app.handle_password_result("pass", cb);
        }
        app.cursor = 1;
        app.expand_current();
        {
            let cb = app.password_prompt.take().unwrap().callback;
            app.handle_password_result("pass", cb);
        }

        let dir = tempfile::tempdir().unwrap();
        let storage = duir_core::FileStorage::new(dir.path()).unwrap();
        app.save_all(&storage);

        let loaded = storage.load("test").unwrap();
        assert!(loaded.items[0].cipher.is_some());
        assert!(loaded.items[0].items.is_empty());
        // In memory still unlocked
        assert!(app.files[0].data.items[0].unlocked);
    }

    #[test]
    fn collapse_updates_editor() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.load_editor();
        app.save_editor();
        app.cmd_collapse();
        let content = app.editor.as_ref().unwrap().content();
        assert!(content.contains("duir:collapsed"));
    }

    #[test]
    fn delete_incomplete_requires_confirm() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.delete_current();
        assert!(app.pending_delete);
        assert_eq!(app.files[0].data.items[0].title, "Branch 1");
    }

    #[test]
    fn delete_completed_leaf_immediate() {
        let mut app = make_app_with_tree();
        app.cursor = 2; // Child 1.1 (Done)
        app.delete_current();
        assert!(!app.pending_delete);
        assert_eq!(app.files[0].data.items[0].items[0].title, "Child 1.2");
    }

    #[test]
    fn filter_hides_rows() {
        let mut app = make_app_with_tree();
        let total = app.rows.len();
        app.filter_text = "Child 1.1".to_owned();
        app.apply_filter();
        assert!(app.rows.len() < total);
    }

    #[test]
    fn filter_clear_restores() {
        let mut app = make_app_with_tree();
        let total = app.rows.len();
        app.filter_text = "Child 1.1".to_owned();
        app.apply_filter();
        app.filter_text.clear();
        app.apply_filter();
        assert_eq!(app.rows.len(), total);
    }

    #[test]
    fn new_sibling_starts_editing() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        app.new_sibling();
        assert!(app.editing_title);
        assert_eq!(app.files[0].data.items.len(), 4);
    }

    #[test]
    fn new_child_starts_editing() {
        let mut app = make_app_with_tree();
        app.cursor = 1;
        let old = app.files[0].data.items[0].items.len();
        app.new_child();
        assert!(app.editing_title);
        assert_eq!(app.files[0].data.items[0].items.len(), old + 1);
    }

    #[test]
    fn save_preserves_unencrypted_data() {
        let mut app = make_app_with_tree();
        app.files[0].modified = true;
        let dir = tempfile::tempdir().unwrap();
        let storage = duir_core::FileStorage::new(dir.path()).unwrap();
        app.save_all(&storage);
        let loaded = storage.load("test").unwrap();
        assert_eq!(loaded.items[0].title, "Branch 1");
        assert_eq!(loaded.items[0].note, "branch1 note");
        assert_eq!(loaded.items[0].items[0].title, "Child 1.1");
        assert_eq!(loaded.items[1].title, "Branch 2");
        assert_eq!(loaded.items[2].title, "Branch 3");
    }
}

use ratatui::style::{Color, Modifier, Style};
use ratatui::text::{Line, Span};

/// Highlight markdown content, returning owned lines suitable for use after
/// the source `content` string has been dropped.
pub fn highlight_lines(content: &str, cursor_row: usize, cursor_col: usize) -> Vec<Line<'static>> {
    let mut in_fence = false;
    content
        .lines()
        .enumerate()
        .map(|(i, line)| {
            let styled = if line.starts_with("```") {
                in_fence = !in_fence;
                owned_line(line, Style::default().fg(Color::DarkGray))
            } else if in_fence {
                owned_line(line, Style::default().fg(Color::Green))
            } else {
                highlight_md(line)
            };
            if i == cursor_row {
                apply_cursor(line, cursor_col)
            } else {
                styled
            }
        })
        .collect()
}

fn owned_line(text: &str, style: Style) -> Line<'static> {
    Line::from(Span::styled(text.to_owned(), style))
}

fn apply_cursor(line: &str, col: usize) -> Line<'static> {
    let rev = Style::default().add_modifier(Modifier::REVERSED);
    if line.is_empty() {
        return Line::from(Span::styled(" ".to_owned(), rev));
    }
    let col = col.min(line.len());
    if col >= line.len() {
        Line::from(vec![Span::raw(line.to_owned()), Span::styled(" ".to_owned(), rev)])
    } else {
        Line::from(vec![
            Span::raw(line[..col].to_owned()),
            Span::styled(line[col..=col].to_owned(), rev),
            Span::raw(line[col + 1..].to_owned()),
        ])
    }
}

fn highlight_md(line: &str) -> Line<'static> {
    let base = Style::default();

    // Headings
    if line.strip_prefix("### ").is_some() {
        return owned_line(line, base.fg(Color::Yellow).add_modifier(Modifier::BOLD));
    }
    if line.strip_prefix("## ").is_some() {
        return owned_line(line, base.fg(Color::LightCyan).add_modifier(Modifier::BOLD));
    }
    if line.strip_prefix("# ").is_some() {
        return owned_line(
            line,
            base.fg(Color::LightCyan)
                .add_modifier(Modifier::BOLD | Modifier::UNDERLINED),
        );
    }
    if line.starts_with('#') {
        return owned_line(line, base.fg(Color::Yellow));
    }

    // Blockquote
    if line.starts_with("> ") {
        return owned_line(line, base.fg(Color::DarkGray).add_modifier(Modifier::ITALIC));
    }

    // Horizontal rule
    let trimmed = line.trim();
    if trimmed == "---" || trimmed == "***" || trimmed == "___" {
        return owned_line(line, base.fg(Color::DarkGray));
    }

    // Checkbox items
    let stripped = line.trim_start();
    let indent = &line[..line.len() - stripped.len()];
    if let Some(rest) = stripped.strip_prefix("- [x] ") {
        return Line::from(vec![
            Span::styled(format!("{indent}- "), base),
            Span::styled("[x]".to_owned(), base.fg(Color::Green)),
            Span::styled(
                format!(" {rest}"),
                base.add_modifier(Modifier::CROSSED_OUT | Modifier::DIM),
            ),
        ]);
    }
    if let Some(rest) = stripped.strip_prefix("- [ ] ") {
        return Line::from(vec![
            Span::styled(format!("{indent}- "), base),
            Span::styled("[ ]".to_owned(), base.fg(Color::Red)),
            Span::styled(format!(" {rest}"), base),
        ]);
    }
    if let Some(rest) = stripped.strip_prefix("- [-] ") {
        return Line::from(vec![
            Span::styled(format!("{indent}- "), base),
            Span::styled("[-]".to_owned(), base.fg(Color::Yellow)),
            Span::styled(format!(" {rest}"), base),
        ]);
    }

    // Bullet list
    if stripped.starts_with("- ") || stripped.starts_with("* ") {
        let rest = &stripped[2..];
        return Line::from(vec![
            Span::styled(format!("{indent}• "), base.fg(Color::Cyan)),
            Span::raw(rest.to_owned()),
        ]);
    }

    // Inline markup
    render_inline(line, base)
}

#[allow(clippy::too_many_lines)]
fn render_inline(line: &str, base: Style) -> Line<'static> {
    let mut spans: Vec<Span<'static>> = Vec::new();
    let mut chars = line.char_indices().peekable();
    let mut plain_start = 0;

    while let Some(&(i, ch)) = chars.peek() {
        match ch {
            '`' => {
                push_plain(&mut spans, line, plain_start, i, base);
                chars.next();
                let start = peek_pos(&mut chars, line.len());
                let mut end = start;
                while let Some(&(idx, c)) = chars.peek() {
                    if c == '`' {
                        end = idx;
                        chars.next();
                        break;
                    }
                    end = idx + c.len_utf8();
                    chars.next();
                }
                spans.push(Span::styled(line[start..end].to_owned(), base.fg(Color::Green)));
                plain_start = peek_pos(&mut chars, line.len());
            }
            '*' => {
                push_plain(&mut spans, line, plain_start, i, base);
                chars.next();
                if chars.peek().is_some_and(|&(_, c)| c == '*') {
                    chars.next();
                    let start = peek_pos(&mut chars, line.len());
                    let mut end = start;
                    while let Some(&(idx, c)) = chars.peek() {
                        if c == '*' {
                            end = idx;
                            chars.next();
                            if chars.peek().is_some_and(|&(_, c2)| c2 == '*') {
                                chars.next();
                            }
                            break;
                        }
                        end = idx + c.len_utf8();
                        chars.next();
                    }
                    spans.push(Span::styled(
                        line[start..end].to_owned(),
                        base.add_modifier(Modifier::BOLD),
                    ));
                } else {
                    let start = peek_pos(&mut chars, line.len());
                    let mut end = start;
                    while let Some(&(idx, c)) = chars.peek() {
                        if c == '*' {
                            end = idx;
                            chars.next();
                            break;
                        }
                        end = idx + c.len_utf8();
                        chars.next();
                    }
                    spans.push(Span::styled(
                        line[start..end].to_owned(),
                        base.add_modifier(Modifier::ITALIC),
                    ));
                }
                plain_start = peek_pos(&mut chars, line.len());
            }
            '[' => {
                push_plain(&mut spans, line, plain_start, i, base);
                chars.next();
                let text_start = peek_pos(&mut chars, line.len());
                let mut text_end = text_start;
                let mut found_link = false;
                while let Some(&(idx, c)) = chars.peek() {
                    if c == ']' {
                        text_end = idx;
                        chars.next();
                        if chars.peek().is_some_and(|&(_, c2)| c2 == '(') {
                            chars.next();
                            let url_start = peek_pos(&mut chars, line.len());
                            let mut url_end = url_start;
                            while let Some(&(idx2, c2)) = chars.peek() {
                                if c2 == ')' {
                                    url_end = idx2;
                                    chars.next();
                                    break;
                                }
                                url_end = idx2 + c2.len_utf8();
                                chars.next();
                            }
                            spans.push(Span::styled(
                                line[text_start..text_end].to_owned(),
                                base.fg(Color::LightBlue).add_modifier(Modifier::UNDERLINED),
                            ));
                            spans.push(Span::styled(
                                line[url_start..url_end].to_owned(),
                                base.fg(Color::DarkGray),
                            ));
                            found_link = true;
                        }
                        break;
                    }
                    text_end = idx + c.len_utf8();
                    chars.next();
                }
                if !found_link {
                    spans.push(Span::styled(line[i..text_end].to_owned(), base));
                }
                plain_start = peek_pos(&mut chars, line.len());
            }
            _ => {
                chars.next();
            }
        }
    }

    if plain_start < line.len() {
        spans.push(Span::styled(line[plain_start..].to_owned(), base));
    }

    if spans.is_empty() {
        owned_line(line, base)
    } else {
        Line::from(spans)
    }
}

fn push_plain(spans: &mut Vec<Span<'static>>, line: &str, start: usize, end: usize, style: Style) {
    if start < end {
        spans.push(Span::styled(line[start..end].to_owned(), style));
    }
}

fn peek_pos(chars: &mut std::iter::Peekable<std::str::CharIndices<'_>>, default: usize) -> usize {
    chars.peek().map_or(default, |&(idx, _)| idx)
}

use crossterm::event::{KeyCode, KeyEvent, KeyModifiers};
use ratatui::layout::Rect;
use ratatui::style::{Color, Modifier, Style};
use ratatui::text::{Line, Span};
use ratatui::widgets::{Block, Borders};
use tui_textarea::{CursorMove, TextArea};

/// Vim-like mode for the note editor.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum EditorMode {
    Normal,
    Insert,
    Visual,
    Command,
    Search,
}

/// Wraps `tui_textarea::TextArea` with vim-like keybindings.
pub struct NoteEditor<'a> {
    pub textarea: TextArea<'a>,
    pub mode: EditorMode,
    pub command_buf: String,
    pub line_numbers: bool,
    pub dirty: bool,
    pub status: String,
    pending_count: Option<usize>,
    pending_op: Option<char>,
    command_history: Vec<String>,
    history_index: Option<usize>,
    completer: crate::completer::Completer,
    pub viewport_height: u16,
}

impl NoteEditor<'_> {
    #[must_use]
    pub fn new(content: &str) -> Self {
        let lines: Vec<String> = if content.is_empty() {
            vec![String::new()]
        } else {
            content.lines().map(String::from).collect()
        };
        let mut textarea = TextArea::new(lines);
        textarea.set_cursor_line_style(Style::default());
        textarea.set_cursor_style(Style::default().add_modifier(Modifier::REVERSED));
        textarea.set_selection_style(Style::default().bg(Color::DarkGray).fg(Color::Yellow));
        textarea.set_search_style(Style::default().bg(Color::Yellow).fg(Color::Black));
        textarea.set_tab_length(4);

        Self {
            textarea,
            mode: EditorMode::Normal,
            command_buf: String::new(),
            line_numbers: false,
            dirty: false,
            status: String::new(),
            pending_count: None,
            pending_op: None,
            command_history: Vec::new(),
            history_index: None,
            completer: crate::completer::Completer::new(crate::completer::EDITOR_COMMANDS),
            viewport_height: 24,
        }
    }

    #[must_use]
    pub fn content(&self) -> String {
        self.textarea.lines().join("\n")
    }

    pub fn set_block(&mut self, title: &str, focused: bool) {
        let border_style = if focused {
            Style::default().add_modifier(Modifier::BOLD)
        } else {
            Style::default()
        };
        let mode_str = match self.mode {
            EditorMode::Normal => "NORMAL",
            EditorMode::Insert => "INSERT",
            EditorMode::Visual => "VISUAL",
            EditorMode::Command | EditorMode::Search => "COMMAND",
        };
        self.textarea.set_block(
            Block::default()
                .title(format!("{title} [{mode_str}]"))
                .borders(Borders::ALL)
                .border_style(border_style),
        );
    }

    #[must_use]
    pub fn status_line(&self) -> Line<'_> {
        match self.mode {
            EditorMode::Command => {
                let mut spans = vec![
                    Span::raw(":"),
                    Span::styled(&self.command_buf, Style::default().add_modifier(Modifier::BOLD)),
                    Span::raw("▏"),
                ];
                if !self.completer.matches.is_empty() {
                    spans.push(Span::raw("  "));
                    for (i, m) in self.completer.matches.iter().enumerate() {
                        let style = if self.completer.selected == Some(i) {
                            Style::default().bg(Color::DarkGray).fg(Color::Yellow)
                        } else {
                            Style::default().fg(Color::DarkGray)
                        };
                        spans.push(Span::styled(format!(" {m} "), style));
                    }
                }
                Line::from(spans)
            }
            EditorMode::Search => Line::from(vec![
                Span::raw("/"),
                Span::styled(&self.command_buf, Style::default().add_modifier(Modifier::BOLD)),
                Span::raw("▏"),
            ]),
            _ if !self.status.is_empty() => Line::styled(&self.status, Style::default().fg(Color::DarkGray)),
            _ => Line::raw(""),
        }
    }

    pub fn handle_key(&mut self, key: KeyEvent) -> bool {
        match self.mode {
            EditorMode::Normal => self.handle_normal(key),
            EditorMode::Insert => self.handle_insert(key),
            EditorMode::Visual => self.handle_visual(key),
            EditorMode::Command | EditorMode::Search => self.handle_command_input(key),
        }
    }

    fn count(&mut self) -> usize {
        self.pending_count.take().unwrap_or(1)
    }

    const fn page_half(&self) -> usize {
        (self.viewport_height as usize) / 2
    }

    fn enter_insert(&mut self) {
        self.mode = EditorMode::Insert;
        self.pending_count = None;
        self.pending_op = None;
        self.textarea
            .set_cursor_style(Style::default().add_modifier(Modifier::REVERSED).fg(Color::Green));
    }

    fn enter_normal(&mut self) {
        self.mode = EditorMode::Normal;
        self.pending_count = None;
        self.pending_op = None;
        self.textarea.cancel_selection();
        self.textarea
            .set_cursor_style(Style::default().add_modifier(Modifier::REVERSED));
    }

    #[allow(clippy::too_many_lines)]
    fn handle_normal(&mut self, key: KeyEvent) -> bool {
        // Ctrl+U / Ctrl+D for half-page scroll (before count/operator handling)
        if key.modifiers.contains(KeyModifiers::CONTROL) {
            return match key.code {
                KeyCode::Char('u') => {
                    let n = self.page_half();
                    for _ in 0..n {
                        self.textarea.move_cursor(CursorMove::Up);
                    }
                    true
                }
                KeyCode::Char('d') => {
                    let n = self.page_half();
                    for _ in 0..n {
                        self.textarea.move_cursor(CursorMove::Down);
                    }
                    true
                }
                KeyCode::Char('r') => {
                    self.textarea.redo();
                    self.dirty = true;
                    true
                }
                _ => false,
            };
        }

        // Accumulate count prefix (digits)
        if let KeyCode::Char(c @ '1'..='9') = key.code
            && self.pending_op.is_none()
        {
            let digit = (c as usize) - ('0' as usize);
            self.pending_count = Some(self.pending_count.unwrap_or(0) * 10 + digit);
            return true;
        }
        if key.code == KeyCode::Char('0') && self.pending_count.is_some() && self.pending_op.is_none() {
            let val = self.pending_count.unwrap_or(0) * 10;
            self.pending_count = Some(val);
            return true;
        }

        // Handle pending operator (d, y)
        if let Some(op) = self.pending_op {
            self.pending_op = None;
            return match (op, key.code) {
                ('d', KeyCode::Char('d')) => {
                    let n = self.count();
                    self.delete_lines(n);
                    true
                }
                ('y', KeyCode::Char('y')) => {
                    let n = self.count();
                    self.yank_lines(n);
                    true
                }
                _ => {
                    self.pending_count = None;
                    false
                }
            };
        }

        match key.code {
            // Operators that wait for second key
            KeyCode::Char('d') => {
                self.pending_op = Some('d');
                true
            }
            KeyCode::Char('y') => {
                self.pending_op = Some('y');
                true
            }

            // Mode switches
            KeyCode::Char('i') => {
                self.enter_insert();
                true
            }
            KeyCode::Char('a') => {
                self.textarea.move_cursor(CursorMove::Forward);
                self.enter_insert();
                true
            }
            KeyCode::Char('A') => {
                self.textarea.move_cursor(CursorMove::End);
                self.enter_insert();
                true
            }
            KeyCode::Char('I') => {
                self.textarea.move_cursor(CursorMove::Head);
                self.enter_insert();
                true
            }
            KeyCode::Char('o') => {
                self.textarea.move_cursor(CursorMove::End);
                self.textarea.insert_newline();
                self.auto_indent();
                self.enter_insert();
                self.dirty = true;
                true
            }
            KeyCode::Char('O') => {
                self.textarea.move_cursor(CursorMove::Head);
                self.textarea.insert_newline();
                self.textarea.move_cursor(CursorMove::Up);
                self.enter_insert();
                self.dirty = true;
                true
            }
            KeyCode::Char('v') => {
                self.mode = EditorMode::Visual;
                self.pending_count = None;
                self.textarea.start_selection();
                true
            }
            KeyCode::Char('V') => {
                // Line-wise visual: select from head of current line
                self.mode = EditorMode::Visual;
                self.pending_count = None;
                self.textarea.move_cursor(CursorMove::Head);
                self.textarea.start_selection();
                self.textarea.move_cursor(CursorMove::End);
                true
            }
            KeyCode::Char(':') => {
                self.mode = EditorMode::Command;
                self.command_buf.clear();
                true
            }
            KeyCode::Char('/') => {
                self.mode = EditorMode::Search;
                self.command_buf.clear();
                true
            }

            // Navigation (with count)
            KeyCode::Char('h') | KeyCode::Left => {
                let n = self.count();
                for _ in 0..n {
                    self.textarea.move_cursor(CursorMove::Back);
                }
                true
            }
            KeyCode::Char('j') | KeyCode::Down => {
                let n = self.count();
                for _ in 0..n {
                    self.textarea.move_cursor(CursorMove::Down);
                }
                true
            }
            KeyCode::Char('k') | KeyCode::Up => {
                let n = self.count();
                for _ in 0..n {
                    self.textarea.move_cursor(CursorMove::Up);
                }
                true
            }
            KeyCode::Char('l') | KeyCode::Right => {
                let n = self.count();
                for _ in 0..n {
                    self.textarea.move_cursor(CursorMove::Forward);
                }
                true
            }
            KeyCode::Char('0') => {
                self.textarea.move_cursor(CursorMove::Head);
                true
            }
            KeyCode::Char('$') => {
                self.textarea.move_cursor(CursorMove::End);
                true
            }
            KeyCode::Char('w') => {
                let n = self.count();
                for _ in 0..n {
                    self.textarea.move_cursor(CursorMove::WordForward);
                }
                true
            }
            KeyCode::Char('b') => {
                let n = self.count();
                for _ in 0..n {
                    self.textarea.move_cursor(CursorMove::WordBack);
                }
                true
            }
            KeyCode::Char('g') => {
                self.textarea.move_cursor(CursorMove::Top);
                true
            }
            KeyCode::Char('G') => {
                self.textarea.move_cursor(CursorMove::Bottom);
                true
            }
            KeyCode::PageUp => {
                let n = self.page_half();
                for _ in 0..n {
                    self.textarea.move_cursor(CursorMove::Up);
                }
                true
            }
            KeyCode::PageDown => {
                let n = self.page_half();
                for _ in 0..n {
                    self.textarea.move_cursor(CursorMove::Down);
                }
                true
            }

            // Single-key editing (with count)
            KeyCode::Char('x') => {
                let n = self.count();
                for _ in 0..n {
                    self.textarea.delete_next_char();
                }
                self.dirty = true;
                true
            }
            KeyCode::Char('u') => {
                self.textarea.undo();
                self.dirty = true;
                true
            }
            KeyCode::Char('>') => {
                let n = self.count();
                self.indent_lines(n);
                true
            }
            KeyCode::Char('<') => {
                let n = self.count();
                self.unindent_lines(n);
                true
            }
            KeyCode::Char('p') => {
                self.textarea.paste();
                self.dirty = true;
                true
            }
            KeyCode::Char('P') => {
                // Paste before (move to line start, paste, then move up)
                self.textarea.move_cursor(CursorMove::Head);
                self.textarea.insert_newline();
                self.textarea.move_cursor(CursorMove::Up);
                self.textarea.paste();
                self.dirty = true;
                true
            }
            KeyCode::Char('n') => {
                self.textarea.search_forward(false);
                true
            }
            KeyCode::Char('N') => {
                self.textarea.search_back(false);
                true
            }
            KeyCode::Enter if key.modifiers.contains(KeyModifiers::SHIFT) => {
                self.open_url_at_cursor();
                true
            }
            _ => {
                self.pending_count = None;
                false
            }
        }
    }

    fn delete_lines(&mut self, n: usize) {
        for _ in 0..n {
            self.textarea.move_cursor(CursorMove::Head);
            self.textarea.start_selection();
            self.textarea.move_cursor(CursorMove::Down);
            self.textarea.cut();
        }
        self.dirty = true;
    }

    fn yank_lines(&mut self, n: usize) {
        self.textarea.move_cursor(CursorMove::Head);
        self.textarea.start_selection();
        for _ in 0..n {
            self.textarea.move_cursor(CursorMove::Down);
        }
        self.textarea.copy();
        self.textarea.cancel_selection();
        self.sync_system_clipboard();
        self.status = format!("{n} line(s) yanked");
    }

    fn handle_insert(&mut self, key: KeyEvent) -> bool {
        if key.code == KeyCode::Esc {
            self.enter_normal();
        } else if key.code == KeyCode::Enter {
            self.textarea.insert_newline();
            self.auto_indent();
            self.dirty = true;
        } else if key.code == KeyCode::Tab {
            // Insert spaces to next tab stop
            let (_, col) = self.textarea.cursor();
            let tab_width = self.textarea.tab_length() as usize;
            let spaces = tab_width - (col % tab_width);
            self.textarea.insert_str(" ".repeat(spaces));
            self.dirty = true;
        } else if key.code == KeyCode::Backspace {
            // If cursor is on leading whitespace, delete back to previous tab stop
            let (row, col) = self.textarea.cursor();
            let line = self.textarea.lines().get(row).cloned().unwrap_or_default();
            let leading_ws = line.len() - line.trim_start().len();
            let tab_width = self.textarea.tab_length() as usize;
            if col > 0 && col <= leading_ws && col % tab_width == 0 {
                for _ in 0..tab_width {
                    self.textarea.delete_char();
                }
            } else {
                self.textarea.delete_char();
            }
            self.dirty = true;
        } else {
            self.textarea.input(key);
            self.dirty = true;
        }
        true
    }

    fn handle_visual(&mut self, key: KeyEvent) -> bool {
        match key.code {
            KeyCode::Esc => {
                self.enter_normal();
                true
            }
            KeyCode::Char('h') | KeyCode::Left => {
                self.textarea.move_cursor(CursorMove::Back);
                true
            }
            KeyCode::Char('j') | KeyCode::Down => {
                self.textarea.move_cursor(CursorMove::Down);
                true
            }
            KeyCode::Char('k') | KeyCode::Up => {
                self.textarea.move_cursor(CursorMove::Up);
                true
            }
            KeyCode::Char('l') | KeyCode::Right => {
                self.textarea.move_cursor(CursorMove::Forward);
                true
            }
            KeyCode::Char('w') => {
                self.textarea.move_cursor(CursorMove::WordForward);
                true
            }
            KeyCode::Char('b') => {
                self.textarea.move_cursor(CursorMove::WordBack);
                true
            }
            KeyCode::Char('$') => {
                self.textarea.move_cursor(CursorMove::End);
                true
            }
            KeyCode::Char('0') => {
                self.textarea.move_cursor(CursorMove::Head);
                true
            }
            KeyCode::Char('G') => {
                self.textarea.move_cursor(CursorMove::Bottom);
                true
            }
            KeyCode::Char('g') => {
                self.textarea.move_cursor(CursorMove::Top);
                true
            }
            KeyCode::Char('y') => {
                self.textarea.copy();
                self.sync_system_clipboard();
                self.enter_normal();
                "yanked".clone_into(&mut self.status);
                true
            }
            KeyCode::Char('d' | 'x') => {
                self.textarea.cut();
                self.sync_system_clipboard();
                self.enter_normal();
                self.dirty = true;
                true
            }
            KeyCode::Char('>') => {
                self.indent_selection();
                self.enter_normal();
                true
            }
            KeyCode::Char('<') => {
                self.unindent_selection();
                self.enter_normal();
                true
            }
            _ => false,
        }
    }

    fn handle_command_input(&mut self, key: KeyEvent) -> bool {
        match key.code {
            KeyCode::Esc => {
                self.history_index = None;
                self.completer.matches.clear();
                self.enter_normal();
                true
            }
            KeyCode::Enter => {
                let cmd = self.command_buf.clone();
                let is_search = self.mode == EditorMode::Search;
                if !cmd.trim().is_empty() {
                    let entry = if is_search { format!("/{cmd}") } else { cmd.clone() };
                    self.command_history.push(entry);
                }
                self.history_index = None;
                self.completer.matches.clear();
                self.enter_normal();
                if is_search {
                    self.execute_search(&cmd);
                } else {
                    self.execute_editor_command(&cmd);
                }
                true
            }
            KeyCode::Tab => {
                if self.mode == EditorMode::Command {
                    self.completer.update(&self.command_buf);
                    if let Some(completion) = self.completer.next() {
                        self.command_buf = completion.to_owned();
                    }
                }
                true
            }
            KeyCode::BackTab => {
                if self.mode == EditorMode::Command {
                    self.completer.update(&self.command_buf);
                    if let Some(completion) = self.completer.prev() {
                        self.command_buf = completion.to_owned();
                    }
                }
                true
            }
            KeyCode::Up => {
                if self.command_history.is_empty() {
                    return true;
                }
                let idx = self
                    .history_index
                    .map_or(self.command_history.len() - 1, |i| i.saturating_sub(1));
                self.history_index = Some(idx);
                let entry = self.command_history[idx].clone();
                entry
                    .strip_prefix('/')
                    .unwrap_or(&entry)
                    .clone_into(&mut self.command_buf);
                true
            }
            KeyCode::Down => {
                if let Some(idx) = self.history_index {
                    if idx + 1 < self.command_history.len() {
                        self.history_index = Some(idx + 1);
                        let entry = self.command_history[idx + 1].clone();
                        entry
                            .strip_prefix('/')
                            .unwrap_or(&entry)
                            .clone_into(&mut self.command_buf);
                    } else {
                        self.history_index = None;
                        self.command_buf.clear();
                    }
                }
                true
            }
            KeyCode::Backspace => {
                if self.command_buf.is_empty() {
                    self.history_index = None;
                    self.completer.matches.clear();
                    self.enter_normal();
                } else {
                    self.command_buf.pop();
                    if self.mode == EditorMode::Command {
                        self.completer.update(&self.command_buf);
                        self.completer.reset_selection();
                    }
                }
                true
            }
            KeyCode::Char(c) => {
                self.history_index = None;
                self.command_buf.push(c);
                if self.mode == EditorMode::Search {
                    self.textarea.set_search_pattern(&self.command_buf).ok();
                } else {
                    self.completer.update(&self.command_buf);
                    self.completer.reset_selection();
                }
                true
            }
            _ => false,
        }
    }

    fn execute_search(&mut self, pattern: &str) {
        if pattern.is_empty() {
            self.textarea.set_search_pattern("").ok();
            return;
        }
        self.textarea.set_search_pattern(pattern).ok();
        self.textarea.search_forward(false);
        self.status = format!("/{pattern}");
    }

    fn execute_editor_command(&mut self, cmd: &str) {
        let cmd = cmd.trim();

        // :set commands
        if let Some(rest) = cmd.strip_prefix("set ") {
            self.execute_set(rest.trim());
            return;
        }

        // Standalone !command (no range) — insert output at cursor
        if let Some(shell_cmd) = cmd.strip_prefix('!')
            && !shell_cmd.is_empty()
        {
            self.insert_shell_output(shell_cmd);
            return;
        }

        // Parse range + command
        let total_lines = self.textarea.lines().len();
        let (row, _) = self.textarea.cursor();
        match parse_ex_command(cmd, row, total_lines) {
            Some(ExCommand::Yank { start, end }) => self.ex_yank(start, end),
            Some(ExCommand::Delete { start, end }) => self.ex_delete(start, end),
            Some(ExCommand::Substitute {
                start,
                end,
                pattern,
                replacement,
                flags,
            }) => {
                self.ex_substitute(start, end, &pattern, &replacement, &flags);
            }
            Some(ExCommand::Shell { start, end, command }) => {
                self.ex_shell(start, end, &command);
            }
            None => {
                self.status = format!("Unknown: {cmd}");
            }
        }
    }

    fn execute_set(&mut self, arg: &str) {
        match arg {
            "nu" | "num" | "number" => {
                self.line_numbers = true;
                self.textarea
                    .set_line_number_style(Style::default().fg(Color::DarkGray));
                "line numbers on".clone_into(&mut self.status);
            }
            "nonu" | "nonum" | "nonumber" => {
                self.line_numbers = false;
                self.textarea.remove_line_number();
                "line numbers off".clone_into(&mut self.status);
            }
            "li" | "list" | "noli" | "nolist" => {
                "list mode not yet supported".clone_into(&mut self.status);
            }
            _ => self.status = format!("Unknown set: {arg}"),
        }
    }

    fn ex_yank(&mut self, start: usize, end: usize) {
        let lines = self.textarea.lines();
        let end = end.min(lines.len().saturating_sub(1));
        let text: String = (start..=end)
            .filter_map(|i| lines.get(i))
            .cloned()
            .collect::<Vec<_>>()
            .join("\n");
        self.textarea.set_yank_text(&text);
        crate::clipboard::copy_to_clipboard(&text);
        let count = end - start + 1;
        self.status = format!("{count} line(s) yanked");
    }

    fn ex_delete(&mut self, start: usize, end: usize) {
        let mut lines = self.textarea.lines().to_vec();
        let total = lines.len();
        let end = end.min(total.saturating_sub(1));
        if start > end || start >= total {
            return;
        }
        let count = end - start + 1;
        lines.drain(start..=end);
        if lines.is_empty() {
            lines.push(String::new());
        }
        self.replace_all_lines(lines, start.min(total.saturating_sub(count + 1)));
        self.dirty = true;
        self.status = format!("{count} line(s) deleted");
    }

    fn ex_substitute(&mut self, start: usize, end: usize, pattern: &str, replacement: &str, flags: &str) {
        let global = flags.contains('g');
        let re = match regex::Regex::new(pattern) {
            Ok(r) => r,
            Err(e) => {
                self.status = format!("Bad regex: {e}");
                return;
            }
        };

        let lines = self.textarea.lines().to_vec();
        let total = lines.len();
        let end = end.min(total.saturating_sub(1));
        let mut count = 0usize;
        let mut new_lines = lines.clone();

        for i in start..=end {
            if i < new_lines.len() {
                let old = &lines[i];
                let new = if global {
                    re.replace_all(old, replacement).to_string()
                } else {
                    re.replace(old, replacement).to_string()
                };
                if *old != new {
                    count += 1;
                    new_lines[i] = new;
                }
            }
        }

        if count > 0 {
            // Rebuild textarea with new content
            let cursor = self.textarea.cursor();
            self.textarea = TextArea::new(new_lines);
            self.textarea.set_cursor_line_style(Style::default());
            self.textarea
                .set_cursor_style(Style::default().add_modifier(Modifier::REVERSED));
            self.textarea
                .set_selection_style(Style::default().bg(Color::DarkGray).fg(Color::Yellow));
            self.textarea
                .set_search_style(Style::default().bg(Color::Yellow).fg(Color::Black));
            self.textarea.set_tab_length(4);
            if self.line_numbers {
                self.textarea
                    .set_line_number_style(Style::default().fg(Color::DarkGray));
            }
            // Restore cursor position
            self.textarea.move_cursor(CursorMove::Top);
            for _ in 0..cursor.0.min(self.textarea.lines().len().saturating_sub(1)) {
                self.textarea.move_cursor(CursorMove::Down);
            }
            self.dirty = true;
        }
        self.status = format!("{count} substitution(s)");
    }

    fn insert_shell_output(&mut self, command: &str) {
        match std::process::Command::new("sh").arg("-c").arg(command).output() {
            Ok(out) => {
                let text = String::from_utf8_lossy(&out.stdout);
                for line in text.lines() {
                    self.textarea.insert_str(line);
                    self.textarea.insert_newline();
                }
                self.dirty = true;
                self.status = format!("!{command}: {} line(s)", text.lines().count());
            }
            Err(e) => self.status = format!("Shell error: {e}"),
        }
    }
    fn ex_shell(&mut self, start: usize, end: usize, command: &str) {
        let lines = self.textarea.lines().to_vec();
        let total = lines.len();
        let end = end.min(total.saturating_sub(1));

        let input: String = (start..=end)
            .filter_map(|i| lines.get(i))
            .cloned()
            .collect::<Vec<_>>()
            .join("\n");

        let output = match std::process::Command::new("sh")
            .arg("-c")
            .arg(command)
            .stdin(std::process::Stdio::piped())
            .stdout(std::process::Stdio::piped())
            .stderr(std::process::Stdio::piped())
            .spawn()
        {
            Ok(mut child) => {
                use std::io::Write;
                if let Some(stdin) = child.stdin.as_mut() {
                    stdin.write_all(input.as_bytes()).ok();
                }
                drop(child.stdin.take());
                match child.wait_with_output() {
                    Ok(out) => String::from_utf8_lossy(&out.stdout).to_string(),
                    Err(e) => {
                        self.status = format!("Shell error: {e}");
                        return;
                    }
                }
            }
            Err(e) => {
                self.status = format!("Shell error: {e}");
                return;
            }
        };

        // Replace the range with output
        let mut new_lines: Vec<String> = Vec::new();
        for (i, line) in lines.iter().enumerate() {
            if i == start {
                for out_line in output.lines() {
                    new_lines.push(out_line.to_owned());
                }
            } else if i > end || i < start {
                new_lines.push(line.clone());
            }
        }
        if new_lines.is_empty() {
            new_lines.push(String::new());
        }

        self.textarea = TextArea::new(new_lines);
        self.textarea.set_cursor_line_style(Style::default());
        self.textarea
            .set_cursor_style(Style::default().add_modifier(Modifier::REVERSED));
        self.textarea
            .set_selection_style(Style::default().bg(Color::DarkGray).fg(Color::Yellow));
        self.textarea
            .set_search_style(Style::default().bg(Color::Yellow).fg(Color::Black));
        self.textarea.set_tab_length(4);
        if self.line_numbers {
            self.textarea
                .set_line_number_style(Style::default().fg(Color::DarkGray));
        }
        self.textarea.move_cursor(CursorMove::Top);
        for _ in 0..start.min(self.textarea.lines().len().saturating_sub(1)) {
            self.textarea.move_cursor(CursorMove::Down);
        }
        self.dirty = true;
        let out_count = output.lines().count();
        self.status = format!("!{command}: {out_count} line(s)");
    }

    fn indent_lines(&mut self, count: usize) {
        let (row, _) = self.textarea.cursor();
        let total = self.textarea.lines().len();
        let end = (row + count).min(total);
        let mut lines = self.textarea.lines().to_vec();
        for line in lines.iter_mut().take(end).skip(row) {
            *line = format!("    {line}");
        }
        self.replace_all_lines(lines, row);
        self.dirty = true;
    }

    fn unindent_lines(&mut self, count: usize) {
        let (row, _) = self.textarea.cursor();
        let total = self.textarea.lines().len();
        let end = (row + count).min(total);
        let mut lines = self.textarea.lines().to_vec();
        for line in lines.iter_mut().take(end).skip(row) {
            if line.starts_with("    ") {
                *line = line[4..].to_owned();
            } else if line.starts_with('\t') {
                *line = line[1..].to_owned();
            } else {
                let trimmed = line.trim_start();
                let ws = line.len() - trimmed.len();
                if ws > 0 {
                    *line = trimmed.to_owned();
                }
            }
        }
        self.replace_all_lines(lines, row);
        self.dirty = true;
    }

    fn indent_selection(&mut self) {
        if let Some(((start_row, _), (end_row, _))) = self.textarea.selection_range() {
            let mut lines = self.textarea.lines().to_vec();
            for line in lines.iter_mut().take(end_row + 1).skip(start_row) {
                *line = format!("    {line}");
            }
            self.replace_all_lines(lines, start_row);
            self.dirty = true;
        }
    }

    fn unindent_selection(&mut self) {
        if let Some(((start_row, _), (end_row, _))) = self.textarea.selection_range() {
            let mut lines = self.textarea.lines().to_vec();
            for line in lines.iter_mut().take(end_row + 1).skip(start_row) {
                if line.starts_with("    ") {
                    *line = line[4..].to_owned();
                } else if line.starts_with('\t') {
                    *line = line[1..].to_owned();
                } else {
                    let trimmed = line.trim_start();
                    *line = trimmed.to_owned();
                }
            }
            self.replace_all_lines(lines, start_row);
            self.dirty = true;
        }
    }

    fn replace_all_lines(&mut self, lines: Vec<String>, restore_row: usize) {
        self.textarea = TextArea::new(lines);
        self.textarea.set_cursor_line_style(Style::default());
        self.textarea
            .set_cursor_style(Style::default().add_modifier(Modifier::REVERSED));
        self.textarea
            .set_selection_style(Style::default().bg(Color::DarkGray).fg(Color::Yellow));
        self.textarea
            .set_search_style(Style::default().bg(Color::Yellow).fg(Color::Black));
        self.textarea.set_tab_length(4);
        if self.line_numbers {
            self.textarea
                .set_line_number_style(Style::default().fg(Color::DarkGray));
        }
        self.textarea.move_cursor(CursorMove::Top);
        for _ in 0..restore_row.min(self.textarea.lines().len().saturating_sub(1)) {
            self.textarea.move_cursor(CursorMove::Down);
        }
    }

    fn sync_system_clipboard(&self) {
        let text = self.textarea.yank_text();
        if !text.is_empty() {
            crate::clipboard::copy_to_clipboard(&text);
        }
    }
    fn auto_indent(&mut self) {
        let (row, _) = self.textarea.cursor();
        if row == 0 {
            return;
        }
        let prev_line = self.textarea.lines().get(row - 1).cloned().unwrap_or_default();
        let indent: String = prev_line.chars().take_while(|c| c.is_whitespace()).collect();
        if !indent.is_empty() {
            self.textarea.insert_str(&indent);
        }
    }

    pub fn render(&mut self, frame: &mut ratatui::Frame, area: Rect) {
        self.viewport_height = area.height.saturating_sub(2);
        if self.mode == EditorMode::Insert {
            frame.render_widget(&self.textarea, area);
        } else {
            let content = self.content();
            let (cursor_row, cursor_col) = self.textarea.cursor();
            let block = self.textarea.block().cloned();
            let lines = crate::markdown_view::highlight_lines(&content, cursor_row, cursor_col);
            #[allow(clippy::cast_possible_truncation)]
            let scroll_offset = cursor_row.saturating_sub(self.viewport_height as usize / 2) as u16;
            let mut paragraph = ratatui::widgets::Paragraph::new(lines)
                .wrap(ratatui::widgets::Wrap { trim: false })
                .scroll((scroll_offset, 0));
            if let Some(b) = block {
                paragraph = paragraph.block(b);
            }
            frame.render_widget(paragraph, area);
        }
    }

    /// Try to open URL under cursor.
    pub fn open_url_at_cursor(&self) {
        let (row, col) = self.textarea.cursor();
        if let Some(line) = self.textarea.lines().get(row)
            && let Some(url) = extract_url(line, col)
        {
            open_in_browser(&url);
        }
    }
}

/// Extract a URL from a line at the given column position.
fn extract_url(line: &str, col: usize) -> Option<String> {
    // Find all URLs in the line, return the one containing or nearest to cursor
    for prefix in ["https://", "http://"] {
        let mut search_from = 0;
        while let Some(pos) = line[search_from..].find(prefix) {
            let url_start = search_from + pos;
            let url_end = line[url_start..]
                .find(|c: char| c.is_whitespace() || c == ')' || c == '>' || c == '"' || c == '\'')
                .map_or(line.len(), |e| url_start + e);
            if col >= url_start && col <= url_end {
                return Some(line[url_start..url_end].to_owned());
            }
            search_from = url_end;
        }
    }
    // Also check markdown links: [text](url)
    if let Some(paren_start) = line.find("](") {
        let url_start = paren_start + 2;
        if let Some(paren_end) = line[url_start..].find(')') {
            let url = &line[url_start..url_start + paren_end];
            if (url.starts_with("http://") || url.starts_with("https://")) && col <= url_start + paren_end {
                return Some(url.to_owned());
            }
        }
    }
    None
}

fn open_in_browser(url: &str) {
    #[cfg(target_os = "macos")]
    let cmd = "open";
    #[cfg(target_os = "linux")]
    let cmd = "xdg-open";
    #[cfg(target_os = "windows")]
    let cmd = "start";

    std::process::Command::new(cmd)
        .arg(url)
        .stdin(std::process::Stdio::null())
        .stdout(std::process::Stdio::null())
        .stderr(std::process::Stdio::null())
        .spawn()
        .ok();
}
/// Parsed ex-command with resolved line range.
enum ExCommand {
    Yank {
        start: usize,
        end: usize,
    },
    Delete {
        start: usize,
        end: usize,
    },
    Substitute {
        start: usize,
        end: usize,
        pattern: String,
        replacement: String,
        flags: String,
    },
    Shell {
        start: usize,
        end: usize,
        command: String,
    },
}

/// Parse a vim ex-command string like `1,$y`, `.,+5s/foo/bar/g`, `.,.+3!sort`.
/// `cursor_row` is 0-indexed, `total_lines` is the line count.
fn parse_ex_command(cmd: &str, cursor_row: usize, total_lines: usize) -> Option<ExCommand> {
    let cmd = cmd.trim();

    // Split into range part and command part
    // Find where the command starts (first alpha or !)
    let cmd_start = cmd
        .find(|c: char| c.is_ascii_alphabetic() || c == '!' || c == 's')
        .unwrap_or(cmd.len());

    let range_str = cmd[..cmd_start].trim();
    let cmd_part = &cmd[cmd_start..];

    let (start, end) = parse_range(range_str, cursor_row, total_lines)?;

    if cmd_part.starts_with('y') {
        return Some(ExCommand::Yank { start, end });
    }
    if cmd_part.starts_with('d') {
        return Some(ExCommand::Delete { start, end });
    }
    if let Some(rest) = cmd_part.strip_prefix('s') {
        return parse_substitute(rest).map(|(pattern, replacement, flags)| ExCommand::Substitute {
            start,
            end,
            pattern,
            replacement,
            flags,
        });
    }
    cmd_part.strip_prefix('!').map(|rest| ExCommand::Shell {
        start,
        end,
        command: rest.to_owned(),
    })
}

/// Parse a range like `1,$` or `.,.+5` or `%` or empty (current line).
/// Returns 0-indexed (start, end) inclusive.
fn parse_range(range: &str, cursor: usize, total: usize) -> Option<(usize, usize)> {
    if range.is_empty() {
        return Some((cursor, cursor));
    }
    if range == "%" {
        return Some((0, total.saturating_sub(1)));
    }

    let parts: Vec<&str> = range.splitn(2, ',').collect();
    match parts.len() {
        1 => {
            let addr = parse_address(parts[0].trim(), cursor, total)?;
            Some((addr, addr))
        }
        2 => {
            let start = parse_address(parts[0].trim(), cursor, total)?;
            let end = parse_address(parts[1].trim(), cursor, total)?;
            Some((start, end))
        }
        _ => None,
    }
}

/// Parse a single address: `.`, `$`, a number, or `.+N`, `.-N`.
fn parse_address(addr: &str, cursor: usize, total: usize) -> Option<usize> {
    if addr == "." {
        return Some(cursor);
    }
    if addr == "$" {
        return Some(total.saturating_sub(1));
    }
    if let Ok(n) = addr.parse::<usize>() {
        return Some(n.saturating_sub(1)); // vim is 1-indexed
    }
    // Relative: .+N, .-N
    if let Some(rest) = addr.strip_prefix(".+") {
        let offset: usize = rest.parse().ok()?;
        return Some((cursor + offset).min(total.saturating_sub(1)));
    }
    if let Some(rest) = addr.strip_prefix(".-") {
        let offset: usize = rest.parse().ok()?;
        return Some(cursor.saturating_sub(offset));
    }
    // Just +N or -N relative to cursor
    if let Some(rest) = addr.strip_prefix('+') {
        let offset: usize = rest.parse().ok()?;
        return Some((cursor + offset).min(total.saturating_sub(1)));
    }
    if let Some(rest) = addr.strip_prefix('-') {
        let offset: usize = rest.parse().ok()?;
        return Some(cursor.saturating_sub(offset));
    }
    None
}

/// Parse `s` command body: `/pattern/replacement/flags`
fn parse_substitute(s: &str) -> Option<(String, String, String)> {
    if s.is_empty() {
        return None;
    }
    let delim = s.chars().next()?;
    let rest = &s[delim.len_utf8()..];
    let parts: Vec<&str> = rest.splitn(3, delim).collect();
    if parts.len() < 2 {
        return None;
    }
    let pattern = parts[0].to_owned();
    let replacement = parts[1].to_owned();
    let flags = parts.get(2).unwrap_or(&"").to_string();
    Some((pattern, replacement, flags))
}

use ratatui::buffer::Buffer;
use ratatui::layout::Rect;
use ratatui::style::{Modifier, Style};
use ratatui::text::{Line, Span};
use ratatui::widgets::{Block, Paragraph, Widget, Wrap};

/// Simple markdown-aware note renderer for the TUI.
/// Renders bold (**text**), italic (*text*), and code (`text`) with terminal styles.
pub struct NoteView<'a> {
    content: &'a str,
    block: Option<Block<'a>>,
    scroll: u16,
}

impl<'a> NoteView<'a> {
    #[must_use]
    pub const fn new(content: &'a str) -> Self {
        Self {
            content,
            block: None,
            scroll: 0,
        }
    }

    #[must_use]
    pub fn block(mut self, block: Block<'a>) -> Self {
        self.block = Some(block);
        self
    }

    #[must_use]
    pub const fn scroll(mut self, offset: u16) -> Self {
        self.scroll = offset;
        self
    }
}

impl Widget for NoteView<'_> {
    fn render(self, area: Rect, buf: &mut Buffer) {
        let lines: Vec<Line<'_>> = self.content.lines().map(|line| render_md_line(line)).collect();

        let mut paragraph = Paragraph::new(lines)
            .wrap(Wrap { trim: false })
            .scroll((self.scroll, 0));

        if let Some(block) = self.block {
            paragraph = paragraph.block(block);
        }

        paragraph.render(area, buf);
    }
}

fn render_md_line(line: &str) -> Line<'_> {
    let mut spans = Vec::new();
    let mut chars = line.char_indices().peekable();
    let mut plain_start = 0;

    while let Some(&(i, ch)) = chars.peek() {
        match ch {
            '*' => {
                // Flush plain text before this
                if i > plain_start {
                    spans.push(Span::raw(&line[plain_start..i]));
                }
                chars.next();
                if chars.peek().is_some_and(|&(_, c)| c == '*') {
                    // Bold: **text**
                    chars.next();
                    let start = chars.peek().map_or(line.len(), |&(idx, _)| idx);
                    let mut end = start;
                    while let Some(&(idx, c)) = chars.peek() {
                        if c == '*' {
                            end = idx;
                            chars.next();
                            if chars.peek().is_some_and(|&(_, c2)| c2 == '*') {
                                chars.next();
                                break;
                            }
                        } else {
                            end = idx + c.len_utf8();
                            chars.next();
                        }
                    }
                    spans.push(Span::styled(
                        &line[start..end],
                        Style::default().add_modifier(Modifier::BOLD),
                    ));
                } else {
                    // Italic: *text*
                    let start = chars.peek().map_or(line.len(), |&(idx, _)| idx);
                    let mut end = start;
                    while let Some(&(idx, c)) = chars.peek() {
                        if c == '*' {
                            end = idx;
                            chars.next();
                            break;
                        }
                        end = idx + c.len_utf8();
                        chars.next();
                    }
                    spans.push(Span::styled(
                        &line[start..end],
                        Style::default().add_modifier(Modifier::ITALIC),
                    ));
                }
                plain_start = chars.peek().map_or(line.len(), |&(idx, _)| idx);
            }
            '`' => {
                if i > plain_start {
                    spans.push(Span::raw(&line[plain_start..i]));
                }
                chars.next();
                let start = chars.peek().map_or(line.len(), |&(idx, _)| idx);
                let mut end = start;
                while let Some(&(idx, c)) = chars.peek() {
                    if c == '`' {
                        end = idx;
                        chars.next();
                        break;
                    }
                    end = idx + c.len_utf8();
                    chars.next();
                }
                spans.push(Span::styled(
                    &line[start..end],
                    Style::default().add_modifier(Modifier::DIM),
                ));
                plain_start = chars.peek().map_or(line.len(), |&(idx, _)| idx);
            }
            _ => {
                chars.next();
            }
        }
    }

    if plain_start < line.len() {
        spans.push(Span::raw(&line[plain_start..]));
    }

    Line::from(spans)
}

use crossterm::event::{KeyCode, KeyEvent};
use ratatui::layout::Rect;
use ratatui::style::{Color, Modifier, Style};
use ratatui::text::{Line, Span};
use ratatui::widgets::{Block, Borders, Clear, Paragraph, Wrap};

/// Password prompt modal state.
pub struct PasswordPrompt {
    pub title: String,
    pub input: String,
    pub callback: PasswordAction,
}

/// What to do after password is entered.
pub enum PasswordAction {
    Decrypt { file_index: usize, path: Vec<usize> },
    Encrypt { file_index: usize, path: Vec<usize> },
    ChangePassword { file_index: usize, path: Vec<usize> },
}

/// Result of handling a key in the password prompt.
pub enum PromptResult {
    /// Still typing.
    Pending,
    /// User pressed Enter with this password.
    Submitted(String),
    /// User pressed Esc.
    Cancelled,
}

impl PasswordPrompt {
    #[must_use]
    pub fn new(title: &str, callback: PasswordAction) -> Self {
        Self {
            title: title.to_owned(),
            input: String::new(),
            callback,
        }
    }

    /// Handle a key event.
    pub fn handle_key(&mut self, key: KeyEvent) -> PromptResult {
        match key.code {
            KeyCode::Enter => PromptResult::Submitted(self.input.clone()),
            KeyCode::Esc => PromptResult::Cancelled,
            KeyCode::Backspace => {
                self.input.pop();
                PromptResult::Pending
            }
            KeyCode::Char(c) => {
                self.input.push(c);
                PromptResult::Pending
            }
            _ => PromptResult::Pending,
        }
    }

    /// Render the password prompt.
    pub fn render(&self, frame: &mut ratatui::Frame, area: Rect) {
        let w = 50.min(area.width.saturating_sub(4));
        let h = 6;
        let x = area.x + (area.width.saturating_sub(w)) / 2;
        let y = area.y + (area.height.saturating_sub(h)) / 2;
        let popup = Rect::new(x, y, w, h);

        frame.render_widget(Clear, popup);

        let masked: String = "•".repeat(self.input.len());
        let lines = vec![
            Line::raw(""),
            Line::from(vec![
                Span::raw("  Password: "),
                Span::styled(format!("{masked}▏"), Style::default().add_modifier(Modifier::BOLD)),
            ]),
            Line::styled(
                "  Enter to confirm, Esc to cancel",
                Style::default().fg(Color::DarkGray),
            ),
            Line::raw(""),
        ];

        let block = Block::default()
            .title(format!(" {} ", self.title))
            .borders(Borders::ALL)
            .border_style(Style::default().fg(Color::Yellow));

        let paragraph = Paragraph::new(lines).block(block).wrap(Wrap { trim: false });
        frame.render_widget(paragraph, popup);
    }
}

use duir_core::Completion;
use ratatui::buffer::Buffer;
use ratatui::layout::Rect;
use ratatui::style::{Color, Modifier, Style};
use ratatui::text::{Line, Span};
use ratatui::widgets::{Block, StatefulWidget, Widget};

use crate::app::App;

/// Renders the tree pane.
pub struct TreeView<'a> {
    block: Option<Block<'a>>,
}

impl<'a> TreeView<'a> {
    #[must_use]
    pub const fn new() -> Self {
        Self { block: None }
    }

    #[must_use]
    pub fn block(mut self, block: Block<'a>) -> Self {
        self.block = Some(block);
        self
    }
}

impl StatefulWidget for TreeView<'_> {
    type State = App;

    #[allow(clippy::cast_possible_truncation)]
    #[allow(clippy::too_many_lines)]
    fn render(self, area: Rect, buf: &mut Buffer, state: &mut Self::State) {
        let inner = self.block.as_ref().map_or(area, |block| {
            let inner = block.inner(area);
            block.clone().render(area, buf);
            inner
        });

        let visible_height = inner.height as usize;
        if state.rows.is_empty() || visible_height == 0 {
            return;
        }

        // Adjust scroll to keep cursor visible
        if state.cursor < state.scroll_offset {
            state.scroll_offset = state.cursor;
        }
        if state.cursor >= state.scroll_offset + visible_height {
            state.scroll_offset = state.cursor - visible_height + 1;
        }

        let end = (state.scroll_offset + visible_height).min(state.rows.len());

        for (vi, ri) in (state.scroll_offset..end).enumerate() {
            let row = &state.rows[ri];
            let y = inner.y + vi as u16;
            let is_selected = ri == state.cursor;

            let indent = "  ".repeat(row.depth);

            let arrow = if row.has_children {
                if row.expanded { "▼ " } else { "▶ " }
            } else {
                "  "
            };

            let lock_icon = if row.locked {
                "🔒"
            } else if row.encrypted {
                "🔓"
            } else if row.has_encrypted_children && !row.expanded {
                "🔐"
            } else {
                ""
            };

            let checkbox = if row.is_file_root {
                String::new()
            } else {
                match row.completed {
                    Completion::Open => "☐ ".to_owned(),
                    Completion::Done => "☑ ".to_owned(),
                    Completion::Partial => "◐ ".to_owned(),
                }
            };

            let prefix = format!("{indent}{arrow}{checkbox}{lock_icon}");
            let prefix_width = prefix.chars().count();

            let title = if is_selected && state.editing_title {
                let pos = state.edit_cursor.min(state.edit_buffer.len());
                format!("{}▏{}", &state.edit_buffer[..pos], &state.edit_buffer[pos..])
            } else {
                row.title.clone()
            };

            let stats_label = if row.stats_text.is_empty() {
                String::new()
            } else {
                format!(" {}", row.stats_text)
            };

            let imp = if row.important { " !" } else { "" };

            let mut style = Style::default();
            if row.completed == Completion::Done {
                style = style.add_modifier(Modifier::CROSSED_OUT | Modifier::DIM);
            } else if row.important && !row.has_children {
                style = style.add_modifier(Modifier::BOLD);
            }

            // Content after prefix: title + stats + padding to fill line
            let content = format!("{title}{stats_label}{imp}");
            let content_width = content.chars().count();
            let total_width = inner.width as usize;
            let pad_len = total_width.saturating_sub(prefix_width + content_width);
            let padding = " ".repeat(pad_len);

            if is_selected {
                let select_all = state.editing_title && state.edit_select_all;
                let title_style = if select_all {
                    Style::default().fg(Color::Yellow).bg(Color::DarkGray)
                } else if state.editing_title {
                    Style::default().fg(Color::White).add_modifier(Modifier::UNDERLINED)
                } else {
                    style.fg(Color::LightCyan).add_modifier(Modifier::UNDERLINED)
                };
                let trail_style = if select_all {
                    Style::default().bg(Color::DarkGray)
                } else {
                    Style::default().fg(Color::DarkGray).add_modifier(Modifier::UNDERLINED)
                };

                let line = Line::from(vec![
                    Span::raw(prefix),
                    Span::styled(content, title_style),
                    Span::styled(padding, trail_style),
                ]);
                buf.set_line(inner.x, y, &line, inner.width);
            } else {
                let line = Line::from(vec![
                    Span::raw(prefix),
                    Span::styled(title, style),
                    Span::styled(
                        format!("{stats_label}{imp}"),
                        Style::default().add_modifier(Modifier::DIM),
                    ),
                ]);
                buf.set_line(inner.x, y, &line, inner.width);
            }
        }
    }
}
